async function salesCustomerServicesView(env, bot, customer) {
  const rows = await env.PASARGUARD_DB.prepare(`
    SELECT o.*,p.title AS plan_title,p.category_id,p.location_id,
           c.title AS category_title,c.emoji AS category_emoji,
           l.title AS location_title,l.emoji AS location_emoji
    FROM sales_orders o
    JOIN sales_plans p ON p.id=o.plan_id
    LEFT JOIN sales_categories c ON c.id=p.category_id
    LEFT JOIN sales_locations l ON l.id=p.location_id
    WHERE o.bot_id=? AND o.customer_id=? AND o.status='delivered' AND o.remote_username IS NOT NULL
    ORDER BY o.updated_at DESC LIMIT 80
  `).bind(bot.id, customer.id).all();
  const services = buildSalesServices(rows.results || []);
  const lines = services.map((service, index) => {
    const limit = Number(service.remote_data_limit || 0);
    const used = Number(service.remote_used_traffic || 0);
    const remaining = limit > 0 ? Math.max(0, limit - used) : 0;
    const expire = service.remote_expire ? botDate(service.remote_expire) : "نامحدود/نامشخص";
    return (index + 1) + ". <b>" + botEscape(service.plan_title) + "</b> · " + botEscape(service.remote_status || "active") + "\n" +
      "   <code>" + botEscape(service.remote_username) + "</code>\n" +
      "   مصرف: <b>" + botGb(used) + "</b> از <b>" + (limit > 0 ? botGb(limit) : "نامحدود") + "</b>" +
      (limit > 0 ? " · باقی‌مانده: <b>" + botGb(remaining) + "</b>" : "") + "\n" +
      "   انقضا: <b>" + botEscape(expire) + "</b>";
  }).join("\n\n") || "هنوز سرویس تحویل‌شده‌ای ندارید.";
  const buttons = [];
  services.slice(0, 8).forEach((service, index) => {
    buttons.push([{ text: "🧭 سرویس " + (index + 1) + " — " + service.remote_username, callback_data: "sale:service:" + service.id }]);
  });
  buttons.push([{ text: "🏠 منوی اصلی", callback_data: "sale:home" }]);
  return { text: "🧭 <b>مرکز سرویس‌های من</b>\n━━━━━━━━━━━━━━\n" + lines, reply_markup: { inline_keyboard: buttons } };
}

async function salesCustomerServiceDetailView(env, bot, customer, serviceId) {
  const target = await getSalesServiceOrder(env, bot, customer, serviceId);
  const rows = await env.PASARGUARD_DB.prepare(`
    SELECT o.*,p.title AS plan_title,p.category_id,p.location_id,
           c.title AS category_title,c.emoji AS category_emoji,
           l.title AS location_title,l.emoji AS location_emoji
    FROM sales_orders o JOIN sales_plans p ON p.id=o.plan_id
    LEFT JOIN sales_categories c ON c.id=p.category_id LEFT JOIN sales_locations l ON l.id=p.location_id
    WHERE o.bot_id=? AND o.customer_id=? AND o.status='delivered' AND o.remote_username=?
    ORDER BY o.updated_at DESC
  `).bind(bot.id, customer.id, target.remote_username).all();
  const service = buildSalesServices(rows.results || [target])[0];
  const limit = Number(service.remote_data_limit || 0), used = Number(service.remote_used_traffic || 0);
  const remaining = limit > 0 ? Math.max(0, limit - used) : 0;
  const expire = service.remote_expire ? botDate(service.remote_expire) : "نامحدود/نامشخص";
  const text = "🧭 <b>جزئیات سرویس</b>\n━━━━━━━━━━━━━━\n" +
    "پلن اولیه: <b>" + botEscape(service.plan_title) + "</b>\n" +
    "نام کاربری: <code>" + botEscape(service.remote_username) + "</code>\n" +
    "وضعیت: <b>" + botEscape(service.remote_status || "active") + "</b>\n" +
    "مصرف‌شده: <b>" + botGb(used) + "</b>\n" +
    "حجم کل: <b>" + (limit > 0 ? botGb(limit) : "نامحدود") + "</b>\n" +
    (limit > 0 ? "باقی‌مانده: <b>" + botGb(remaining) + "</b>\n" : "") +
    "انقضا: <b>" + botEscape(expire) + "</b>\n" +
    "تمدیدها: <b>" + botMoney(service.renewals_count) + "</b> · افزایش حجم: <b>" + botMoney(service.volume_orders_count) + "</b>";
  const buttons = [];
  if (service.subscription_url) buttons.push([{ text: "📋 کپی لینک اشتراک", copy_text: { text: service.subscription_url } }]);
  buttons.push([{ text: "🔄 بروزرسانی اطلاعات", callback_data: "sale:service:refresh:" + service.id }, { text: "🔐 تعویض لینک", callback_data: "sale:service:revoke_confirm:" + service.id }]);
  buttons.push([{ text: "♻️ تمدید", callback_data: "sale:renew:" + service.id }, { text: "➕ افزایش حجم", callback_data: "sale:volume:" + service.id }]);
  buttons.push([{ text: "↩️ سرویس‌های من", callback_data: "sale:services" }]);
  return { text, reply_markup: { inline_keyboard: buttons } };
}

