function parseSalesMiniAppReceipt(body) {
  const source = String(body.file_base64 || body.file_data || "");
  const match = source.match(/^data:([^;,]+);base64,([A-Za-z0-9+/=\s]+)$/);
  if (!match) throw new Error("فایل رسید معتبر نیست");
  const mimeType = cleanText(match[1].toLowerCase(), 100);
  const allowed = new Set(["image/jpeg", "image/png", "image/webp", "application/pdf"]);
  if (!allowed.has(mimeType)) throw new Error("فرمت رسید باید JPG، PNG، WEBP یا PDF باشد");
  const compact = match[2].replace(/\s+/g, "");
  if (compact.length > 7_500_000) throw new Error("حجم رسید بیشتر از حد مجاز است");
  let bytes;
  try { bytes = base64ToBytes(compact); } catch (_) { throw new Error("خواندن فایل رسید ناموفق بود"); }
  if (!bytes.length) throw new Error("فایل رسید خالی است");
  if (bytes.length > 5 * 1024 * 1024) throw new Error("حداکثر حجم رسید ۵ مگابایت است");
  const fallbackExt = mimeType === "application/pdf" ? "pdf" : mimeType.split("/")[1].replace("jpeg", "jpg");
  const safeName = cleanText(body.file_name, 160).replace(/[^a-zA-Z0-9._-]/g, "_") || ("receipt." + fallbackExt);
  return { bytes, mimeType, filename: safeName, caption: cleanText(body.caption, 500) };
}

async function sendResellerOwnerUploadedReceipt(env, bot, kind, row, customer, plan, upload) {
  if (!bot.owner_telegram_id) throw new Error("شناسه مالک ربات ثبت نشده است");
  const isWallet = kind === "wallet";
  const caption = isWallet
    ? "💳 <b>رسید شارژ از مینی‌اپ</b>\n━━━━━━━━━━━━━━\nمشتری: <b>" + botEscape(customer.first_name || customer.username || customer.telegram_id) + "</b>\nشناسه: <code>" + botEscape(customer.telegram_id) + "</code>\nمبلغ: <b>" + botMoney(row.amount_toman) + " تومان</b>\nدرخواست: <code>" + botEscape(row.id) + "</code>"
    : "🧾 <b>رسید سفارش از مینی‌اپ</b>\n━━━━━━━━━━━━━━\nمشتری: <b>" + botEscape(customer.first_name || customer.username || customer.telegram_id) + "</b>\nشناسه: <code>" + botEscape(customer.telegram_id) + "</code>\nنوع: <b>" + (row.order_type === "renewal" ? "تمدید سرویس" : row.order_type === "volume" ? "افزایش حجم" : "خرید سرویس") + "</b>\nپلن: <b>" + botEscape(plan?.title || plan?.plan_title || "پلن فروش") + "</b>\nمبلغ: <b>" + botMoney(row.amount_toman) + " تومان</b>\nسفارش: <code>" + botEscape(row.id) + "</code>";
  const replyMarkup = isWallet
    ? { inline_keyboard: [[{ text: "✅ تأیید شارژ", callback_data: "owner:wallet:approve:" + row.id }, { text: "❌ رد", callback_data: "owner:wallet:reject:" + row.id }], [{ text: "↩️ درخواست‌های شارژ", callback_data: "owner:wallets" }]] }
    : { inline_keyboard: [[{ text: "✅ تأیید و تحویل", callback_data: "owner:approve:" + row.id }, { text: "❌ رد رسید", callback_data: "owner:reject:" + row.id }], [{ text: "↩️ سفارش‌ها", callback_data: "owner:orders" }]] };
  const usePhoto = ["image/jpeg", "image/png"].includes(upload.mimeType);
  const method = usePhoto ? "sendPhoto" : "sendDocument";
  const field = usePhoto ? "photo" : "document";
  const form = new FormData();
  form.set("chat_id", String(bot.owner_telegram_id));
  form.set(field, new Blob([upload.bytes], { type: upload.mimeType }), upload.filename);
  form.set("caption", caption + (upload.caption ? "\n\nتوضیح مشتری: " + botEscape(upload.caption) : ""));
  form.set("parse_mode", "HTML");
  form.set("reply_markup", JSON.stringify(replyMarkup));
  const token = await resellerBotToken(env, bot);
  const response = await fetch("https://api.telegram.org/bot" + token + "/" + method, { method: "POST", body: form });
  const data = await response.json().catch(() => ({}));
  if (!response.ok || data.ok === false) throw new Error(data.description || "ارسال رسید برای نماینده ناموفق بود");
  const result = data.result || {};
  const fileId = usePhoto
    ? String((Array.isArray(result.photo) && result.photo.length ? result.photo[result.photo.length - 1].file_id : "") || "")
    : String(result.document?.file_id || "");
  if (!fileId) throw new Error("شناسه فایل رسید از تلگرام دریافت نشد");
  return { fileId, fileType: usePhoto ? "photo" : "document", messageId: String(result.message_id || "") };
}

async function submitSalesMiniAppReceipt(env, bot, customer, body) {
  const targetType = body.target_type === "wallet" ? "wallet" : "order";
  const targetId = cleanText(body.target_id, 100);
  if (!targetId) throw new Error("شناسه پرداخت مشخص نیست");
  const upload = parseSalesMiniAppReceipt(body);
  const receiptFingerprint = await salesReceiptFingerprint(upload.bytes);
  await ensureUniqueSalesReceipt(env, bot, customer, receiptFingerprint, targetType, targetId);
  if (targetType === "order") {
    const row = await env.PASARGUARD_DB.prepare(`
      SELECT o.*,p.title AS plan_title,p.data_limit_bytes,p.duration_days
      FROM sales_orders o JOIN sales_plans p ON p.id=o.plan_id
      WHERE o.id=? AND o.bot_id=? AND o.customer_id=? AND o.origin='miniapp'
    `).bind(targetId, bot.id, customer.id).first();
    if (!row || row.status !== "awaiting_receipt") throw new Error("این سفارش آماده دریافت رسید نیست");
    const claim = await env.PASARGUARD_DB.prepare("UPDATE sales_orders SET status='receipt_uploading',updated_at=? WHERE id=? AND status='awaiting_receipt'")
      .bind(nowIso(), row.id).run();
    if (!Number(claim?.meta?.changes || 0)) throw new Error("رسید این سفارش هم‌زمان در حال ثبت است");
    try {
      const media = await sendResellerOwnerUploadedReceipt(env, bot, "order", row, customer, { title: row.plan_title }, upload);
      await env.PASARGUARD_DB.prepare(`
        UPDATE sales_orders SET status='pending_review',receipt_file_id=?,receipt_file_type=?,receipt_message_id=?,receipt_caption=?,receipt_unique_id=?,updated_at=?
        WHERE id=? AND status='receipt_uploading'
      `).bind(media.fileId, media.fileType, media.messageId, upload.caption, receiptFingerprint, nowIso(), row.id).run();
      await salesEvent(env, bot.id, customer.id, "miniapp_receipt_submitted", { orderId: row.id });
      return { targetType, targetId: row.id, status: "pending_review" };
    } catch (error) {
      await env.PASARGUARD_DB.prepare("UPDATE sales_orders SET status='awaiting_receipt',updated_at=? WHERE id=? AND status='receipt_uploading'").bind(nowIso(), row.id).run();
      throw error;
    }
  }
  const row = await env.PASARGUARD_DB.prepare(`
    SELECT * FROM sales_wallet_requests WHERE id=? AND bot_id=? AND customer_id=? AND origin='miniapp'
  `).bind(targetId, bot.id, customer.id).first();
  if (!row || row.status !== "awaiting_receipt") throw new Error("این درخواست شارژ آماده دریافت رسید نیست");
  const claim = await env.PASARGUARD_DB.prepare("UPDATE sales_wallet_requests SET status='receipt_uploading',updated_at=? WHERE id=? AND status='awaiting_receipt'")
    .bind(nowIso(), row.id).run();
  if (!Number(claim?.meta?.changes || 0)) throw new Error("رسید این شارژ هم‌زمان در حال ثبت است");
  try {
    const media = await sendResellerOwnerUploadedReceipt(env, bot, "wallet", row, customer, null, upload);
    await env.PASARGUARD_DB.prepare(`
      UPDATE sales_wallet_requests SET status='pending_review',receipt_file_id=?,receipt_file_type=?,receipt_message_id=?,receipt_caption=?,receipt_unique_id=?,updated_at=?
      WHERE id=? AND status='receipt_uploading'
    `).bind(media.fileId, media.fileType, media.messageId, upload.caption, receiptFingerprint, nowIso(), row.id).run();
    await salesEvent(env, bot.id, customer.id, "miniapp_wallet_receipt_submitted", { requestId: row.id });
    return { targetType, targetId: row.id, status: "pending_review" };
  } catch (error) {
    await env.PASARGUARD_DB.prepare("UPDATE sales_wallet_requests SET status='awaiting_receipt',updated_at=? WHERE id=? AND status='receipt_uploading'").bind(nowIso(), row.id).run();
    throw error;
  }
}

async function sendMainBotMedia(env, method, chatId, bytes, filename, mimeType, caption, replyMarkup) {
  const settings = await getSettings(env);
  if (!settings.bot_token) throw new Error("توکن ربات اصلی تنظیم نشده است");
  const form = new FormData();
  form.set("chat_id", String(chatId));
  form.set(method === "sendPhoto" ? "photo" : "document", new Blob([bytes], { type: mimeType || "application/octet-stream" }), filename || "receipt");
  form.set("caption", caption);
  form.set("parse_mode", "HTML");
  form.set("reply_markup", JSON.stringify(replyMarkup));
  const response = await fetch("https://api.telegram.org/bot" + settings.bot_token + "/" + method, { method: "POST", body: form });
  const data = await response.json().catch(() => ({}));
  if (!response.ok || data.ok === false) throw new Error(data.description || "ارسال رسید برای نماینده ناموفق بود");
  return data;
}

async function notifySalesOrderOwner(env, bot, order, customer, plan) {
  const caption = "🧾 <b>رسید جدید ربات فروش</b>\n━━━━━━━━━━━━━━\n" +
    "برند: <b>" + botEscape(bot.brand_name) + "</b>\n" +
    "مشتری: <b>" + botEscape(customer.first_name || customer.username || customer.telegram_id) + "</b>\n" +
    "شناسه: <code>" + botEscape(customer.telegram_id) + "</code>\n" +
    "نوع: <b>" + (order.order_type === "renewal" ? "تمدید سرویس" : order.order_type === "volume" ? "افزایش حجم" : "خرید سرویس") + "</b>\n" +
    "پلن: <b>" + botEscape(plan.title || plan.plan_title || "پلن فروش") + "</b>\n" +
    "مبلغ: <b>" + botMoney(order.amount_toman) + " تومان</b>\n" +
    "سفارش: <code>" + botEscape(order.id) + "</code>";
  const replyMarkup = { inline_keyboard: [[
    { text: "✅ تأیید و تحویل", callback_data: "bot:sales:approve:" + order.id },
    { text: "❌ رد رسید", callback_data: "bot:sales:reject:" + order.id }
  ]] };
  let mediaSent = false;
  try {
    const token = await resellerBotToken(env, bot);
    const fileInfo = await telegramApiWithToken(token, "getFile", { file_id: order.receipt_file_id });
    const filePath = fileInfo?.result?.file_path;
    if (filePath) {
      const response = await fetch("https://api.telegram.org/file/bot" + token + "/" + filePath);
      if (response.ok) {
        const bytes = await response.arrayBuffer();
        const ext = String(filePath).split(".").pop() || (order.receipt_file_type === "photo" ? "jpg" : "bin");
        const method = order.receipt_file_type === "photo" ? "sendPhoto" : "sendDocument";
        const mime = response.headers.get("content-type") || (method === "sendPhoto" ? "image/jpeg" : "application/octet-stream");
        await sendMainBotMedia(env, method, bot.owner_telegram_id, bytes, "receipt." + ext, mime, caption, replyMarkup);
        mediaSent = true;
      }
    }
  } catch (error) {
    await audit(env, bot.user_id, "sales_receipt_media_forward_failed", { orderId: order.id, message: error.message });
  }
  if (!mediaSent) {
    try {
      if (order.receipt_message_id && Number(bot.forward_enabled ?? 1) === 1) {
        await resellerTelegramApi(env, bot, "forwardMessage", {
          chat_id: bot.owner_telegram_id,
          from_chat_id: customer.telegram_id,
          message_id: Number(order.receipt_message_id)
        });
      }
    } catch (_) {}
    await telegramApi(env, "sendMessage", { chat_id: bot.owner_telegram_id, text: caption, parse_mode: "HTML", reply_markup: replyMarkup });
  }
}

