async function adjustSalesCustomerBalance(env, botId, customerId, amount, type, refType, refId, description) {
  const value = Number(amount || 0);
  if (!Number.isSafeInteger(value) || value === 0) throw new Error("مبلغ تغییر موجودی معتبر نیست");
  const ts = nowIso();
  const result = value > 0
    ? await env.PASARGUARD_DB.prepare("UPDATE sales_customers SET wallet_balance=wallet_balance+?,updated_at=? WHERE id=? AND bot_id=?")
      .bind(value, ts, customerId, botId).run()
    : await env.PASARGUARD_DB.prepare("UPDATE sales_customers SET wallet_balance=wallet_balance+?,updated_at=? WHERE id=? AND bot_id=? AND wallet_balance>=?")
      .bind(value, ts, customerId, botId, Math.abs(value)).run();
  if (!Number(result?.meta?.changes || 0)) throw new Error(value < 0 ? "موجودی کیف پول کافی نیست" : "تغییر موجودی انجام نشد");
  const fresh = await env.PASARGUARD_DB.prepare("SELECT wallet_balance FROM sales_customers WHERE id=?").bind(customerId).first();
  await env.PASARGUARD_DB.prepare(`
    INSERT INTO sales_customer_ledger(id,bot_id,customer_id,type,amount,balance_after,ref_type,ref_id,description,created_at)
    VALUES(?,?,?,?,?,?,?,?,?,?)
  `).bind(id("cled"), botId, customerId, type, value, Number(fresh?.wallet_balance || 0), refType || null, refId || null, cleanText(description, 500), ts).run();
  return Number(fresh?.wallet_balance || 0);
}

async function registerSalesReceipt(env, bot, customer, message, session) {
  const order = await env.PASARGUARD_DB.prepare(`
    SELECT o.*,p.title AS plan_title,p.data_limit_bytes,p.duration_days,p.price_toman
    FROM sales_orders o JOIN sales_plans p ON p.id=o.plan_id
    WHERE o.id=? AND o.bot_id=? AND o.customer_id=? AND o.status='awaiting_receipt'
  `).bind(session.data.orderId, bot.id, customer.id).first();
  if (!order) throw new Error("سفارش فعال برای دریافت رسید پیدا نشد");
  let fileId = "", fileType = "", fileUniqueId = "";
  if (Array.isArray(message.photo) && message.photo.length) { const media = message.photo[message.photo.length - 1]; fileId = String(media.file_id || ""); fileUniqueId = String(media.file_unique_id || ""); fileType = "photo"; }
  else if (message.document?.file_id) { fileId = String(message.document.file_id); fileUniqueId = String(message.document.file_unique_id || ""); fileType = "document"; }
  if (!fileId) throw new Error("لطفاً تصویر یا فایل رسید را ارسال کنید");
  const receiptFingerprint = fileUniqueId ? "tg:" + fileUniqueId : "";
  await ensureUniqueSalesReceipt(env, bot, customer, receiptFingerprint, "order", order.id);
  const result = await env.PASARGUARD_DB.prepare(`
    UPDATE sales_orders SET status='pending_review',receipt_file_id=?,receipt_file_type=?,receipt_message_id=?,
      receipt_caption=?,receipt_unique_id=?,updated_at=? WHERE id=? AND status='awaiting_receipt'
  `).bind(fileId, fileType, String(message.message_id || ""), cleanText(message.caption, 500), receiptFingerprint, nowIso(), order.id).run();
  if (!Number(result?.meta?.changes || 0)) throw new Error("این رسید قبلاً ثبت شده است");
  await salesSessionClear(env, bot.id, customer.telegram_id);
  const fullBot = await getResellerBotById(env, bot.id);
  const freshOrder = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_orders WHERE id=?").bind(order.id).first();
  await notifySalesOrderOwner(env, fullBot, freshOrder, customer, order);
  await resellerTelegramApi(env, bot, "sendMessage", {
    chat_id: customer.telegram_id,
    text: "✅ <b>رسید شما ثبت شد</b>\nپس از بررسی نماینده، نتیجه همین‌جا اعلام می‌شود.",
    parse_mode: "HTML",
    reply_markup: { inline_keyboard: [[{ text: "📦 سفارش‌های من", callback_data: "sale:orders" }]] }
  });
  await salesEvent(env, bot.id, customer.id, "receipt_submitted", { orderId: order.id });
}

