function salesGroupIds(location) {
  try {
    const value = JSON.parse(location?.group_ids_json || "[]");
    return Array.isArray(value) ? value.map(Number).filter(Number.isInteger) : [];
  } catch (_) { return []; }
}

async function sendSalesServiceDelivery(env, bot, chatId, data) {
  const link = cleanText(data.subscriptionUrl, 2000);
  const custom = await salesBotText(env, bot.id, "delivery", "لینک را در برنامه موردنظر وارد کنید. این پیام قابل کپی و فوروارد است.");
  const buttons = [];
  if (link) buttons.push([{ text: "📋 کپی واقعی لینک اشتراک", copy_text: { text: link } }]);
  buttons.push([{ text: "📦 سرویس‌های من", callback_data: "sale:orders" }]);
  let caption = "✅ <b>" + botEscape(data.title || "سرویس شما آماده شد") + "</b>\n━━━━━━━━━━━━━━\n" +
    (data.planTitle ? "پلن: <b>" + botEscape(data.planTitle) + "</b>\n" : "") +
    "نام کاربری: <code>" + botEscape(data.username || "") + "</code>\n" +
    (data.volumeBytes != null ? "حجم: <b>" + botGb(data.volumeBytes) + "</b>\n" : "") +
    (data.durationHours != null ? "اعتبار: <b>" + botMoney(data.durationHours) + " ساعت</b>\n" : (data.durationDays != null ? "اعتبار افزوده: <b>" + botMoney(data.durationDays) + " روز</b>\n" : "")) +
    (link ? "\n🔗 لینک اشتراک:\n<code>" + botEscape(link) + "</code>\n" : "") + "\n" + botEscape(custom);
  if (caption.length > 1010) caption = caption.slice(0, 1000) + "…";
  if (link) {
    try { await resellerTelegramApi(env, bot, "sendPhoto", { chat_id: chatId, photo: salesQrUrl(link), caption, parse_mode: "HTML", protect_content: Number(bot.forward_enabled ?? 1) !== 1, reply_markup: { inline_keyboard: buttons } }); return; } catch (_) {}
  }
  await resellerTelegramApi(env, bot, "sendMessage", { chat_id: chatId, text: caption, parse_mode: "HTML", disable_web_page_preview: true, protect_content: Number(bot.forward_enabled ?? 1) !== 1, reply_markup: { inline_keyboard: buttons } });
}

async function rewardSalesReferral(env, bot, order, customer) {
  if (!customer.referrer_customer_id) return;
  const type = String(bot.referral_reward_type || "fixed");
  const reward = type === "percent" ? Math.floor(Math.max(0, Number(order.amount_toman || 0)) * Math.max(0, Math.min(100, Number(bot.referral_reward_percent || 0))) / 100) : Math.max(0, Number(bot.referral_reward_toman || 0));
  if (!reward) return;
  const claim = await env.PASARGUARD_DB.prepare("UPDATE sales_orders SET referral_rewarded=1 WHERE id=? AND referral_rewarded=0").bind(order.id).run();
  if (!Number(claim?.meta?.changes || 0)) return;
  try {
    const balance = await adjustSalesCustomerBalance(env, bot.id, customer.referrer_customer_id, reward, "referral_reward", "sales_order", order.id, "پورسانت خرید موفق زیرمجموعه");
    const referrer = await env.PASARGUARD_DB.prepare("SELECT telegram_id FROM sales_customers WHERE id=?").bind(customer.referrer_customer_id).first();
    if (order.origin !== "miniapp" && referrer?.telegram_id) await resellerTelegramApi(env, bot, "sendMessage", { chat_id: referrer.telegram_id, text: "🎉 <b>پورسانت زیرمجموعه دریافت کردید</b>\nمبلغ: <b>" + botMoney(reward) + " تومان</b>\nموجودی جدید: <b>" + botMoney(balance) + " تومان</b>", parse_mode: "HTML" });
  } catch (error) { await env.PASARGUARD_DB.prepare("UPDATE sales_orders SET referral_rewarded=0 WHERE id=?").bind(order.id).run(); throw error; }
}

function salesCashbackAmount(bot, amountToman) {
  if (Number(bot?.cashback_enabled || 0) !== 1) return 0;
  const amount = Math.max(0, Number(amountToman || 0));
  const minPurchase = Math.max(0, Number(bot.cashback_min_purchase_toman || 0));
  if (!amount || amount < minPurchase) return 0;
  const percent = Math.max(0, Math.min(100, Number(bot.cashback_percent || 0)));
  let reward = Math.floor(amount * percent / 100);
  const cap = Math.max(0, Number(bot.cashback_max_toman || 0));
  if (cap > 0) reward = Math.min(reward, cap);
  return Math.max(0, reward);
}

async function createSalesNotification(env, bot, customer, orderId, type, title, message, dedupeKey, options = {}) {
  const notificationId = id("ntf");
  const insert = await env.PASARGUARD_DB.prepare(`
    INSERT OR IGNORE INTO sales_notifications(
      id,bot_id,customer_id,order_id,type,title,message,status,sent_to_bot,dedupe_key,created_at
    ) VALUES(?,?,?,?,?,?,?,'unread',0,?,?)
  `).bind(notificationId, bot.id, customer.id, orderId || null, cleanText(type, 40), cleanText(title, 180), cleanText(message, 1500), cleanText(dedupeKey, 500), nowIso()).run();
  if (!Number(insert?.meta?.changes || 0)) return { created: false };
  let sentToBot = false;
  if (options.sendBot !== false && customer.telegram_id) {
    const settings = await getSettings(env);
    const appUrl = salesMiniAppUrl(bot, settings);
    const rows = appUrl ? [[{ text: "🔔 مشاهده در مینی‌اپ", web_app: { url: appUrl } }]] : [];
    try {
      await resellerTelegramApi(env, bot, "sendMessage", {
        chat_id: customer.telegram_id,
        text: "🔔 <b>" + botEscape(title) + "</b>\n━━━━━━━━━━━━━━\n" + botEscape(message),
        parse_mode: "HTML",
        disable_web_page_preview: true,
        reply_markup: rows.length ? { inline_keyboard: rows } : undefined
      });
      sentToBot = true;
      await env.PASARGUARD_DB.prepare("UPDATE sales_notifications SET sent_to_bot=1 WHERE id=?").bind(notificationId).run();
    } catch (_) {}
  }
  return { created: true, id: notificationId, sentToBot };
}

async function rewardSalesCashback(env, bot, order, customer) {
  const reward = salesCashbackAmount(bot, order.amount_toman);
  if (!reward) return 0;
  const claim = await env.PASARGUARD_DB.prepare(`
    UPDATE sales_orders SET cashback_rewarded=1,cashback_toman=?,updated_at=?
    WHERE id=? AND cashback_rewarded=0
  `).bind(reward, nowIso(), order.id).run();
  if (!Number(claim?.meta?.changes || 0)) return Number(order.cashback_toman || 0);
  try {
    const balance = await adjustSalesCustomerBalance(env, bot.id, customer.id, reward, "cashback", "sales_order", order.id, "کش‌بک خرید موفق");
    await createSalesNotification(env, bot, customer, order.id, "cashback", "کش‌بک خرید دریافت شد", "مبلغ " + botMoney(reward) + " تومان به کیف پول شما اضافه شد. موجودی جدید: " + botMoney(balance) + " تومان.", "cashback:" + order.id, { sendBot: order.origin !== "miniapp" });
    await salesEvent(env, bot.id, customer.id, "cashback_rewarded", { orderId: order.id, reward, balance });
    return reward;
  } catch (error) {
    await env.PASARGUARD_DB.prepare("UPDATE sales_orders SET cashback_rewarded=0,cashback_toman=0,updated_at=? WHERE id=?").bind(nowIso(), order.id).run();
    throw error;
  }
}


const RESELLER_LOYALTY_PROFILES = Object.freeze({
  standard: Object.freeze({ label: "استاندارد", silver: 500000, gold: 2000000, vip: 5000000, discounts: { silver: 1, gold: 3, vip: 5 } }),
  growth: Object.freeze({ label: "رشد سریع", silver: 250000, gold: 1000000, vip: 3000000, discounts: { silver: 2, gold: 4, vip: 7 } }),
  premium: Object.freeze({ label: "پریمیوم", silver: 1000000, gold: 5000000, vip: 12000000, discounts: { silver: 2, gold: 5, vip: 8 } })
});

function resellerLoyaltyProfile(bot) {
  return RESELLER_LOYALTY_PROFILES[String(bot?.loyalty_profile || "standard")] || RESELLER_LOYALTY_PROFILES.standard;
}

function salesLoyaltyLevelForSpend(bot, spend) {
  const total = Math.max(0, Number(spend || 0));
  if (Number(bot?.loyalty_enabled ?? 1) !== 1) return { level: "bronze", discount: 0 };
  const profile = resellerLoyaltyProfile(bot);
  if (total >= profile.vip) return { level: "vip", discount: profile.discounts.vip };
  if (total >= profile.gold) return { level: "gold", discount: profile.discounts.gold };
  if (total >= profile.silver) return { level: "silver", discount: profile.discounts.silver };
  return { level: "bronze", discount: 0 };
}

function salesLoyaltyLabel(level) {
  return ({ bronze: "برنزی", silver: "نقره‌ای", gold: "طلایی", vip: "VIP" })[String(level || "bronze")] || "برنزی";
}

async function refreshSalesCustomerLoyalty(env, bot, customerId, options = {}) {
  const customer = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_customers WHERE id=? AND bot_id=?").bind(customerId, bot.id).first();
  if (!customer) return null;
  const stats = await env.PASARGUARD_DB.prepare(`
    SELECT COALESCE(SUM(amount_toman),0) AS spend,MAX(COALESCE(reviewed_at,updated_at,created_at)) AS last_purchase
    FROM sales_orders WHERE bot_id=? AND customer_id=? AND status='delivered'
  `).bind(bot.id, customer.id).first();
  const spend = Math.max(0, Number(stats?.spend || 0));
  const next = salesLoyaltyLevelForSpend(bot, spend);
  const previous = String(customer.loyalty_level || "bronze");
  await env.PASARGUARD_DB.prepare(`
    UPDATE sales_customers SET lifetime_spend_toman=?,loyalty_level=?,loyalty_discount_percent=?,last_purchase_at=?,updated_at=?
    WHERE id=? AND bot_id=?
  `).bind(spend, next.level, next.discount, stats?.last_purchase || null, nowIso(), customer.id, bot.id).run();
  if (previous !== next.level && next.level !== "bronze" && options.notify !== false) {
    await createSalesNotification(env, bot, customer, null, "loyalty", "ارتقای سطح باشگاه مشتریان",
      "سطح شما به " + salesLoyaltyLabel(next.level) + " ارتقا یافت و از " + next.discount + "٪ تخفیف خودکار بهره‌مند شدید.",
      "loyalty:" + customer.id + ":" + next.level, { sendBot: true });
  }
  return { spend, level: next.level, discount: next.discount, previous };
}

async function processResellerSalesAutomation(env, limit = 100, onlyBotId = null) {
  const max = Math.max(1, Math.min(300, Number(limit || 100)));
  const botsResult = onlyBotId
    ? await env.PASARGUARD_DB.prepare("SELECT * FROM reseller_bots WHERE id=? AND status='active'").bind(onlyBotId).all()
    : await env.PASARGUARD_DB.prepare("SELECT * FROM reseller_bots WHERE status='active' AND COALESCE(sales_automation_enabled,1)=1 ORDER BY COALESCE(automation_last_run_at,created_at) ASC LIMIT 50").all();
  let bots = 0, abandoned = 0, winback = 0, loyalty = 0, failed = 0;
  for (const bot of botsResult.results || []) {
    if (Number(bot.sales_automation_enabled ?? 1) !== 1 && !onlyBotId) continue;
    bots++;
    try {
      const abandonedMinutes = Math.max(15, Math.min(1440, Number(bot.abandoned_reminder_minutes || 60)));
      const abandonedCutoff = new Date(Date.now() - abandonedMinutes * 60000).toISOString();
      const recentCutoff = new Date(Date.now() - 7 * 86400000).toISOString();
      const pending = await env.PASARGUARD_DB.prepare(`
        SELECT o.id,o.origin,o.amount_toman,o.status,o.customer_id,p.title AS plan_title,
               c.telegram_id,c.first_name,c.username
        FROM sales_orders o JOIN sales_customers c ON c.id=o.customer_id JOIN sales_plans p ON p.id=o.plan_id
        WHERE o.bot_id=? AND o.status IN ('awaiting_receipt','payment_pending') AND o.created_at<=? AND o.created_at>=?
        ORDER BY o.created_at ASC LIMIT ?
      `).bind(bot.id, abandonedCutoff, recentCutoff, Math.min(40, max)).all();
      for (const row of pending.results || []) {
        const notice = await createSalesNotification(env, bot, row, row.id, "abandoned_order", "سفارش شما هنوز تکمیل نشده",
          "پلن «" + row.plan_title + "» با مبلغ " + botMoney(row.amount_toman) + " تومان در انتظار پرداخت یا ثبت رسید است.",
          "automation:abandoned:" + row.id, { sendBot: true });
        if (notice.created) abandoned++;
      }

      const winbackDays = Math.max(7, Math.min(365, Number(bot.winback_days || 30)));
      const winbackCutoff = new Date(Date.now() - winbackDays * 86400000).toISOString();
      const inactive = await env.PASARGUARD_DB.prepare(`
        SELECT c.id,c.telegram_id,c.first_name,c.username,MAX(COALESCE(o.reviewed_at,o.updated_at,o.created_at)) AS last_purchase
        FROM sales_customers c JOIN sales_orders o ON o.customer_id=c.id AND o.bot_id=c.bot_id AND o.status='delivered'
        WHERE c.bot_id=? AND c.status='active'
        GROUP BY c.id HAVING last_purchase<=? ORDER BY last_purchase ASC LIMIT ?
      `).bind(bot.id, winbackCutoff, Math.min(40, max)).all();
      const bucket = new Date().toISOString().slice(0,7);
      for (const row of inactive.results || []) {
        const notice = await createSalesNotification(env, bot, row, null, "winback", "دلمان برایتان تنگ شده",
          "مدتی از آخرین خرید شما گذشته است. پلن‌های تازه و پیشنهادهای فعال را در مینی‌اپ ببینید.",
          "automation:winback:" + row.id + ":" + bucket, { sendBot: true });
        if (notice.created) winback++;
      }

      if (Number(bot.loyalty_enabled ?? 1) === 1) {
        const customers = await env.PASARGUARD_DB.prepare(`
          SELECT DISTINCT customer_id FROM sales_orders WHERE bot_id=? AND status='delivered' ORDER BY updated_at DESC LIMIT ?
        `).bind(bot.id, Math.min(80, max)).all();
        for (const row of customers.results || []) {
          try { await refreshSalesCustomerLoyalty(env, bot, row.customer_id); loyalty++; } catch (_) { failed++; }
        }
      }
      await env.PASARGUARD_DB.prepare("UPDATE reseller_bots SET automation_last_run_at=?,updated_at=? WHERE id=?")
        .bind(nowIso(), nowIso(), bot.id).run();
    } catch (error) {
      failed++;
      try { await audit(env, null, "reseller_sales_automation_failed", { botId: bot.id, message: error.message }); } catch (_) {}
    }
  }
  return { bots, abandoned, winback, loyalty, failed };
}

async function resellerOwnerAutomationView(env, bot, account) {
  resellerRequirePermission(account, "automation");
  const fresh = await getResellerBotById(env, bot.id);
  const profile = resellerLoyaltyProfile(fresh);
  const counts = await env.PASARGUARD_DB.prepare(`
    SELECT
      (SELECT COUNT(*) FROM sales_orders WHERE bot_id=? AND status IN ('awaiting_receipt','payment_pending')) AS pending,
      (SELECT COUNT(*) FROM sales_customers WHERE bot_id=? AND loyalty_level='silver') AS silver_count,
      (SELECT COUNT(*) FROM sales_customers WHERE bot_id=? AND loyalty_level='gold') AS gold_count,
      (SELECT COUNT(*) FROM sales_customers WHERE bot_id=? AND loyalty_level='vip') AS vip_count,
      (SELECT COUNT(*) FROM sales_notifications WHERE bot_id=? AND type IN ('abandoned_order','winback') AND created_at>=?) AS notices_30d
  `).bind(bot.id,bot.id,bot.id,bot.id,bot.id,new Date(Date.now()-30*86400000).toISOString()).first();
  const enabled = Number(fresh.sales_automation_enabled ?? 1) === 1;
  const loyaltyEnabled = Number(fresh.loyalty_enabled ?? 1) === 1;
  return {
    text: "⚡ <b>اتوماسیون فروش و باشگاه مشتریان</b>\n━━━━━━━━━━━━━━\n" +
      "وضعیت پیگیری خودکار: <b>" + (enabled ? "🟢 فعال" : "⏸ غیرفعال") + "</b>\n" +
      "یادآوری سفارش نیمه‌کاره: <b>" + botMoney(fresh.abandoned_reminder_minutes || 60) + " دقیقه</b>\n" +
      "بازگشت مشتری غیرفعال: <b>پس از " + botMoney(fresh.winback_days || 30) + " روز</b>\n" +
      "باشگاه مشتریان: <b>" + (loyaltyEnabled ? "فعال" : "غیرفعال") + "</b> · الگو: <b>" + botEscape(profile.label) + "</b>\n\n" +
      "🏅 نقره‌ای: از <b>" + botMoney(profile.silver) + " تومان</b> · " + profile.discounts.silver + "٪\n" +
      "🥇 طلایی: از <b>" + botMoney(profile.gold) + " تومان</b> · " + profile.discounts.gold + "٪\n" +
      "💎 VIP: از <b>" + botMoney(profile.vip) + " تومان</b> · " + profile.discounts.vip + "٪\n\n" +
      "🛒 سفارش‌های نیمه‌کاره فعلی: <b>" + botMoney(counts?.pending) + "</b>\n" +
      "👥 اعضای باشگاه: نقره‌ای " + botMoney(counts?.silver_count) + " · طلایی " + botMoney(counts?.gold_count) + " · VIP " + botMoney(counts?.vip_count) + "\n" +
      "🔔 پیام‌های خودکار ۳۰ روز اخیر: <b>" + botMoney(counts?.notices_30d) + "</b>\n" +
      "⏱ آخرین اجرا: <b>" + botEscape(fresh.automation_last_run_at ? botDate(fresh.automation_last_run_at) : "هنوز اجرا نشده") + "</b>",
    reply_markup: { inline_keyboard: [
      [{ text: enabled ? "⏸ توقف اتوماسیون" : "▶️ فعال‌کردن اتوماسیون", callback_data: "owner:automation:toggle" }],
      [{ text: "🛒 زمان یادآوری: " + botMoney(fresh.abandoned_reminder_minutes || 60) + " دقیقه", callback_data: "owner:automation:abandoned" }],
      [{ text: "🔁 بازگشت مشتری: " + botMoney(fresh.winback_days || 30) + " روز", callback_data: "owner:automation:winback" }],
      [{ text: loyaltyEnabled ? "🏅 غیرفعال‌کردن باشگاه" : "🏅 فعال‌کردن باشگاه", callback_data: "owner:automation:loyalty" }],
      [{ text: "🎯 الگوی باشگاه: " + profile.label, callback_data: "owner:automation:profile" }],
      [{ text: "⚡ اجرای فوری", callback_data: "owner:automation:run" }, { text: "🔄 بروزرسانی", callback_data: "owner:automation" }],
      [{ text: "↩️ مدیریت", callback_data: "owner:home" }]
    ] }
  };
}


async function resellerOwnerSecurityView(env, bot, account) {
  resellerRequirePermission(account, "security");
  const fresh = await getResellerBotById(env, bot.id);
  const cfg = resellerSecurityConfig(fresh);
  const since = new Date(Date.now() - 86400000).toISOString();
  const stats = await env.PASARGUARD_DB.prepare(`
    SELECT
      (SELECT COUNT(*) FROM sales_security_events WHERE bot_id=? AND created_at>=?) AS events_24h,
      (SELECT COUNT(*) FROM sales_security_events WHERE bot_id=? AND severity IN ('high','critical') AND created_at>=?) AS risky_24h,
      (SELECT COUNT(*) FROM sales_customers WHERE bot_id=? AND status='blocked') AS blocked_users,
      (SELECT COUNT(*) FROM sales_customers WHERE bot_id=? AND risk_score>=25) AS risky_users
  `).bind(bot.id,since,bot.id,since,bot.id,bot.id).first();
  const rows = await env.PASARGUARD_DB.prepare(`
    SELECT e.*,c.telegram_id,c.first_name,c.username FROM sales_security_events e
    LEFT JOIN sales_customers c ON c.id=e.customer_id
    WHERE e.bot_id=? ORDER BY e.created_at DESC LIMIT 8
  `).bind(bot.id).all();
  const recent = (rows.results || []).length ? (rows.results || []).map(item =>
    (item.severity === "critical" ? "🔴" : item.severity === "high" ? "🟠" : item.severity === "warning" ? "🟡" : "🔵") +
    " <b>" + botEscape(item.event_type) + "</b> · " + botEscape(item.first_name || item.username || item.telegram_id || "سیستم") +
    "\n   امتیاز: " + (Number(item.score_delta || 0) >= 0 ? "+" : "") + botMoney(item.score_delta) + " · " + botDate(item.created_at)
  ).join("\n\n") : "رخداد امنیتی ثبت نشده است.";
  return {
    text: "🛡️ <b>امنیت و ضدتقلب</b>\n━━━━━━━━━━━━━━\n" +
      "وضعیت: <b>" + (cfg.enabled ? "🟢 فعال" : "⏸ غیرفعال") + "</b>\n" +
      "فاصله عملیات: <b>" + botMoney(cfg.cooldownSeconds) + " ثانیه</b>\n" +
      "حداکثر سفارش در انتظار: <b>" + botMoney(cfg.maxPendingOrders) + "</b>\n" +
      "سقف سفارش روزانه: <b>" + botMoney(cfg.dailyOrderLimit) + "</b>\n" +
      "سقف شارژ روزانه: <b>" + botMoney(cfg.dailyWalletLimit) + " تومان</b>\n" +
      "رسید تکراری: <b>" + (cfg.duplicateReceiptProtection ? "کنترل می‌شود" : "غیرفعال") + "</b>\n" +
      "مسدودسازی خودکار: <b>" + (cfg.autoBlockRiskScore > 0 ? "از امتیاز " + botMoney(cfg.autoBlockRiskScore) : "غیرفعال") + "</b>\n\n" +
      "📊 رخداد ۲۴ ساعت: <b>" + botMoney(stats?.events_24h) + "</b> · پرخطر: <b>" + botMoney(stats?.risky_24h) + "</b>\n" +
      "🚫 کاربران مسدود: <b>" + botMoney(stats?.blocked_users) + "</b> · دارای ریسک: <b>" + botMoney(stats?.risky_users) + "</b>\n\n" +
      "<b>آخرین رخدادها</b>\n" + recent,
    reply_markup: { inline_keyboard: [
      [{ text: cfg.enabled ? "⏸ توقف حفاظت" : "▶️ فعال‌کردن حفاظت", callback_data: "owner:security:toggle" }],
      [{ text: "⏱ فاصله عملیات: " + cfg.cooldownSeconds + " ثانیه", callback_data: "owner:security:cooldown" }],
      [{ text: "🧾 سفارش در انتظار: " + cfg.maxPendingOrders, callback_data: "owner:security:pending" }],
      [{ text: "📅 سفارش روزانه: " + cfg.dailyOrderLimit, callback_data: "owner:security:daily_orders" }],
      [{ text: "💳 شارژ روزانه: " + botMoney(cfg.dailyWalletLimit), callback_data: "owner:security:wallet_limit" }],
      [{ text: cfg.duplicateReceiptProtection ? "🧾 رسید تکراری: فعال" : "🧾 رسید تکراری: غیرفعال", callback_data: "owner:security:duplicate" }],
      [{ text: "🚦 حد مسدودسازی: " + (cfg.autoBlockRiskScore || "خاموش"), callback_data: "owner:security:threshold" }],
      [{ text: "🧹 پاک‌سازی امتیاز ریسک", callback_data: "owner:security:reset_risk" }],
      [{ text: "🔄 بروزرسانی", callback_data: "owner:security" }, { text: "↩️ مدیریت", callback_data: "owner:home" }]
    ] }
  };
}

async function processSalesServiceNotifications(env, limit = 30) {
  const result = await env.PASARGUARD_DB.prepare(`
    SELECT o.id,o.bot_id,o.customer_id,o.remote_username,o.subscription_url,o.remote_status,
           o.remote_data_limit,o.remote_used_traffic,o.remote_expire,o.remote_online_at,o.remote_last_synced_at,
           c.telegram_id,c.first_name,c.username
    FROM sales_orders o
    JOIN sales_customers c ON c.id=o.customer_id
    JOIN reseller_bots rb ON rb.id=o.bot_id
    WHERE o.status='delivered' AND o.order_type='new' AND o.target_order_id IS NULL
      AND o.remote_username IS NOT NULL AND rb.status='active' AND COALESCE(rb.notifications_enabled,1)=1
    ORDER BY COALESCE(o.remote_last_synced_at,o.updated_at) ASC
    LIMIT ?
  `).bind(Math.max(1, Math.min(100, Number(limit || 30)))).all();
  let checked = 0, created = 0, failed = 0;
  for (const row of result.results || []) {
    checked++;
    try {
      const bot = await getResellerBotById(env, row.bot_id);
      if (!bot || bot.agency_status !== "active") continue;
      const customer = { id: row.customer_id, telegram_id: row.telegram_id, first_name: row.first_name, username: row.username };
      const agency = { id: bot.agency_id, panel_username: bot.panel_username, panel_password_enc: bot.panel_password_enc };
      const remote = await agencyPasarguardRequest(env, agency, "GET", "/api/user/" + encodeURIComponent(row.remote_username));
      const snapshot = salesRemoteSnapshot(remote, row);
      let subscriptionUrl = snapshot.subscriptionUrl;
      if (subscriptionUrl && subscriptionUrl.startsWith("/")) {
        const settings = await getSettings(env);
        subscriptionUrl = pasarguardBaseUrl(settings) + subscriptionUrl;
      }
      await env.PASARGUARD_DB.prepare(`
        UPDATE sales_orders SET subscription_url=CASE WHEN ?<>'' THEN ? ELSE subscription_url END,
          remote_status=?,remote_data_limit=?,remote_used_traffic=?,remote_expire=?,remote_online_at=?,remote_last_synced_at=?
        WHERE bot_id=? AND customer_id=? AND remote_username=? AND status='delivered'
      `).bind(subscriptionUrl, subscriptionUrl, snapshot.status, snapshot.dataLimit, snapshot.usedTraffic, snapshot.expire,
        snapshot.onlineAt, snapshot.syncedAt, bot.id, customer.id, row.remote_username).run();

      const threshold = Math.max(1, Math.min(100, Number(bot.usage_reminder_percent || 80)));
      if (snapshot.dataLimit > 0) {
        const usagePercent = Math.floor(snapshot.usedTraffic * 100 / snapshot.dataLimit);
        if (usagePercent >= threshold) {
          const remaining = Math.max(0, snapshot.dataLimit - snapshot.usedTraffic);
          const notice = await createSalesNotification(env, bot, customer, row.id, "usage", "هشدار مصرف سرویس",
            "مصرف سرویس " + row.remote_username + " به " + usagePercent + "٪ رسیده و " + botGb(remaining) + " باقی مانده است.",
            "usage:" + row.remote_username + ":" + threshold + ":" + snapshot.dataLimit);
          if (notice.created) created++;
        }
      }

      const expiryHours = Math.max(1, Math.min(720, Number(bot.expiry_reminder_hours || 48)));
      if (snapshot.expire) {
        const remainingMs = Date.parse(snapshot.expire) - Date.now();
        if (remainingMs > 0 && remainingMs <= expiryHours * 3600000) {
          const hoursLeft = Math.max(1, Math.ceil(remainingMs / 3600000));
          const notice = await createSalesNotification(env, bot, customer, row.id, "expiry", "اعتبار سرویس رو به پایان است",
            "از اعتبار سرویس " + row.remote_username + " حدود " + hoursLeft + " ساعت باقی مانده است. برای جلوگیری از قطع سرویس، آن را تمدید کنید.",
            "expiry:" + row.remote_username + ":" + snapshot.expire + ":" + expiryHours);
          if (notice.created) created++;
        }
      }

      const status = String(snapshot.status || "").toLowerCase();
      if (["expired", "disabled", "limited"].includes(status)) {
        const notice = await createSalesNotification(env, bot, customer, row.id, "status", "وضعیت سرویس تغییر کرد",
          "وضعیت سرویس " + row.remote_username + " اکنون «" + status + "» است. جزئیات را در مینی‌اپ بررسی کنید.",
          "status:" + row.remote_username + ":" + status + ":" + (snapshot.expire || "none"));
        if (notice.created) created++;
      }
    } catch (_) { failed++; }
  }
  return { checked, created, failed };
}

async function processSalesTicketAutoClose(env, limit = 100) {
  const result = await env.PASARGUARD_DB.prepare(`
    SELECT t.id,t.bot_id,t.customer_id,t.public_code,t.subject,t.updated_at,t.origin,
           rb.ticket_auto_close_hours,c.telegram_id,c.first_name,c.username
    FROM sales_tickets t
    JOIN reseller_bots rb ON rb.id=t.bot_id
    JOIN sales_customers c ON c.id=t.customer_id
    WHERE t.status='answered' AND COALESCE(rb.ticketing_enabled,1)=1
    ORDER BY t.updated_at ASC LIMIT ?
  `).bind(Math.max(1, Math.min(300, Number(limit || 100)))).all();
  let checked = 0, closed = 0;
  for (const row of result.results || []) {
    checked++;
    const hours = Math.max(1, Math.min(720, Number(row.ticket_auto_close_hours || 72)));
    const updatedAt = Date.parse(row.updated_at || "");
    if (!Number.isFinite(updatedAt) || Date.now() - updatedAt < hours * 3600000) continue;
    const ts = nowIso();
    const claim = await env.PASARGUARD_DB.prepare(`
      UPDATE sales_tickets SET status='closed',closed_at=?,updated_at=?
      WHERE id=? AND status='answered'
    `).bind(ts, ts, row.id).run();
    if (!Number(claim?.meta?.changes || 0)) continue;
    closed++;
    const bot = await getResellerBotById(env, row.bot_id);
    if (!bot) continue;
    const customer = { id: row.customer_id, telegram_id: row.telegram_id, first_name: row.first_name, username: row.username };
    await createSalesNotification(
      env, bot, customer, null, "support_closed", "تیکت پشتیبانی بسته شد",
      "تیکت " + row.public_code + " پس از " + hours + " ساعت بدون پاسخ جدید به‌صورت خودکار بسته شد.",
      "ticket_auto_close:" + row.id + ":" + row.updated_at,
      { sendBot: row.origin !== "miniapp" }
    );
    await salesEvent(env, row.bot_id, row.customer_id, "ticket_auto_closed", { ticketId: row.id, hours });
  }
  return { checked, closed };
}

async function provisionSalesOrder(env, ownerUser, orderId) {
  const order = await env.PASARGUARD_DB.prepare(`
    SELECT o.*,p.title AS plan_title,p.data_limit_bytes,p.duration_days,p.price_toman,p.location_id,
           c.id AS customer_record_id,c.telegram_id AS customer_telegram_id,c.username AS customer_username,
           c.first_name AS customer_first_name,c.referrer_customer_id,
           rb.user_id AS owner_user_id,rb.brand_name,rb.bot_token_enc,rb.bot_username,rb.webhook_secret,rb.id AS reseller_bot_id,
           rb.referral_reward_toman,rb.forward_enabled,
           a.id AS agency_id,a.panel_username,a.panel_password_enc,a.status AS agency_status,
           l.group_ids_json
    FROM sales_orders o
    JOIN sales_plans p ON p.id=o.plan_id
    JOIN sales_customers c ON c.id=o.customer_id
    JOIN reseller_bots rb ON rb.id=o.bot_id
    LEFT JOIN reseller_bots parent_rb ON parent_rb.id=rb.parent_bot_id
    JOIN agencies a ON a.id=CASE WHEN rb.parent_bot_id IS NOT NULL THEN parent_rb.agency_id ELSE rb.agency_id END
    LEFT JOIN sales_locations l ON l.id=p.location_id
    WHERE o.id=?
  `).bind(orderId).first();
  if (!order || Number(order.owner_user_id) !== Number(ownerUser.id)) throw new Error("سفارش پیدا نشد");
  const staleProvisioning = order.status === "provisioning" && Date.now() - new Date(order.updated_at).getTime() > 2 * 60 * 1000;
  if (!["pending_review", "provision_failed"].includes(String(order.status)) && !staleProvisioning) throw new Error("این سفارش قابل تأیید نیست");
  if (order.agency_status !== "active") throw new Error("پنل متصل فعال نیست");
  const claim = await env.PASARGUARD_DB.prepare(`
    UPDATE sales_orders SET status='provisioning',error_message=NULL,updated_at=?,reviewed_at=?,reviewed_by=?
    WHERE id=? AND (status IN ('pending_review','provision_failed') OR (status='provisioning' AND updated_at<?))
  `).bind(nowIso(), nowIso(), ownerUser.id, order.id, new Date(Date.now() - 2 * 60 * 1000).toISOString()).run();
  if (!Number(claim?.meta?.changes || 0)) throw new Error("سفارش هم‌زمان در حال پردازش است");
  const agency = { id: order.agency_id, panel_username: order.panel_username, panel_password_enc: order.panel_password_enc };
  const bot = await getResellerBotById(env, order.reseller_bot_id);
  try {
    let created, username, subscriptionUrl = "";
    if (order.order_type === "renewal" || order.order_type === "volume") {
      const target = await env.PASARGUARD_DB.prepare(`
        SELECT * FROM sales_orders WHERE id=? AND bot_id=? AND customer_id=? AND status='delivered'
      `).bind(order.target_order_id, order.bot_id, order.customer_id).first();
      if (!target?.remote_username) throw new Error(order.order_type === "volume" ? "سرویس مقصد افزایش حجم پیدا نشد" : "سرویس مقصد تمدید پیدا نشد");
      username = target.remote_username;
      const current = await agencyPasarguardRequest(env, agency, "GET", "/api/user/" + encodeURIComponent(username));
      const payload = {
        status: "active",
        data_limit: Math.max(0, Number(current?.data_limit || 0)) + Math.max(0, Number(order.data_limit_bytes || 0)),
        note: "Telegram " + order.order_type + " order " + order.id
      };
      if (order.order_type === "renewal" && Number(order.duration_days || 0) > 0) {
        const normalizedExpire = salesRemoteExpireValue(current?.expire);
        const currentExpireTime = normalizedExpire ? Date.parse(normalizedExpire) : 0;
        const baseTime = Math.max(Date.now(), Number.isFinite(currentExpireTime) ? currentExpireTime : 0);
        payload.expire = new Date(baseTime + Number(order.duration_days) * 86400000).toISOString();
      }
      created = await agencyPasarguardRequest(env, agency, "PUT", "/api/user/" + encodeURIComponent(username), payload);
      subscriptionUrl = cleanText(created.subscription_url || current.subscription_url || created?.data?.subscription_url, 2000);
    } else {
      username = normalizeUsername("ord_" + String(order.id).replace(/[^a-zA-Z0-9]/g, "").slice(-24));
      const expiresAt = Number(order.duration_days) > 0 ? new Date(Date.now() + Number(order.duration_days) * 86400000).toISOString() : 0;
      const payload = {
        username,
        status: "active",
        data_limit: Math.max(0, Number(order.data_limit_bytes || 0)),
        expire: expiresAt,
        data_limit_reset_strategy: "no_reset",
        note: "Telegram sales order " + order.id + " / customer " + order.customer_telegram_id
      };
      const groups = salesGroupIds(order);
      if (groups.length) payload.group_ids = groups;
      for (let attempt = 0; attempt < 3 && !created; attempt++) {
        try { created = await agencyPasarguardRequest(env, agency, "POST", "/api/user", payload); }
        catch (error) {
          if (error.status === 409 || /username|already|وجود|تکرار/i.test(String(error.message || ""))) {
            created = await agencyPasarguardRequest(env, agency, "GET", "/api/user/" + encodeURIComponent(username));
            break;
          }
          if (attempt < 2 && (!error.status || error.status >= 500)) continue;
          throw error;
        }
      }
      if (!created) throw new Error("ساخت سرویس پس از چند تلاش ناموفق بود");
      subscriptionUrl = cleanText(created.subscription_url || created?.data?.subscription_url, 2000);
    }
    if (subscriptionUrl && subscriptionUrl.startsWith("/")) {
      const settings = await getSettings(env);
      subscriptionUrl = pasarguardBaseUrl(settings) + subscriptionUrl;
    }
    const remoteId = created?.id || created?.data?.id || "";
    let remoteForSnapshot = created || {};
    try { remoteForSnapshot = await agencyPasarguardRequest(env, agency, "GET", "/api/user/" + encodeURIComponent(username)); } catch (_) {}
    const snapshot = salesRemoteSnapshot(remoteForSnapshot, { subscription_url: subscriptionUrl });
    if (!subscriptionUrl) subscriptionUrl = snapshot.subscriptionUrl;
    await env.PASARGUARD_DB.prepare(`
      UPDATE sales_orders SET status='delivered',remote_user_id=?,remote_username=?,subscription_url=?,
        remote_status=?,remote_data_limit=?,remote_used_traffic=?,remote_expire=?,remote_online_at=?,remote_last_synced_at=?,
        error_message=NULL,updated_at=? WHERE id=?
    `).bind(String(remoteId || ""), username, subscriptionUrl, snapshot.status, snapshot.dataLimit,
      snapshot.usedTraffic, snapshot.expire, snapshot.onlineAt, snapshot.syncedAt, nowIso(), order.id).run();
    await env.PASARGUARD_DB.prepare(`
      UPDATE sales_orders SET subscription_url=?,remote_status=?,remote_data_limit=?,remote_used_traffic=?,
        remote_expire=?,remote_online_at=?,remote_last_synced_at=?
      WHERE bot_id=? AND customer_id=? AND remote_username=? AND status='delivered'
    `).bind(subscriptionUrl, snapshot.status, snapshot.dataLimit, snapshot.usedTraffic, snapshot.expire,
      snapshot.onlineAt, snapshot.syncedAt, order.bot_id, order.customer_id, username).run();
    await salesFinalizePromoForOrder(env, order.id);
    if (order.origin !== "miniapp") {
      await sendSalesServiceDelivery(env, bot, order.customer_telegram_id, {
        title: order.order_type === "renewal" ? "تمدید سرویس با موفقیت انجام شد" : order.order_type === "volume" ? "حجم سرویس با موفقیت افزایش یافت" : "سرویس شما آماده شد",
        planTitle: order.plan_title,
        username,
        volumeBytes: order.data_limit_bytes,
        durationDays: order.duration_days,
        subscriptionUrl
      });
    }
    await rewardSalesReferral(env, bot, order, { id: order.customer_record_id, referrer_customer_id: order.referrer_customer_id });
    let cashbackToman = 0;
    try {
      cashbackToman = await rewardSalesCashback(env, bot, order, { id: order.customer_record_id, telegram_id: order.customer_telegram_id });
    } catch (cashbackError) {
      try { await audit(env, ownerUser.id, "sales_cashback_failed", { orderId: order.id, message: cashbackError.message }); } catch (_) {}
    }
    let loyalty = null;
    try { loyalty = await refreshSalesCustomerLoyalty(env, bot, order.customer_record_id); } catch (_) {}
    await salesEvent(env, bot.id, order.customer_record_id, "order_delivered", { orderId: order.id, username, orderType: order.order_type, cashbackToman, loyalty });
    try { await audit(env, ownerUser.id, "sales_order_delivered", { orderId: order.id, remoteUserId: remoteId, username, orderType: order.order_type, cashbackToman }); } catch (_) {}
    return { ...order, status: "delivered", remote_username: username, subscription_url: subscriptionUrl, cashback_toman: cashbackToman };
  } catch (error) {
    await env.PASARGUARD_DB.prepare("UPDATE sales_orders SET status='provision_failed',error_message=?,updated_at=? WHERE id=?")
      .bind(cleanText(error.message, 1000), nowIso(), order.id).run();
    await audit(env, ownerUser.id, "sales_order_provision_failed", { orderId: order.id, message: error.message });
    throw error;
  }
}

async function purchaseSalesPlanFromWallet(env, bot, customer, planId, options = {}) {
  salesRequireVerifiedPhone(bot, customer);
  const order = await createSalesOrder(env, bot, customer, planId, { ...options, paymentMethod: "wallet", status: "pending_review" });
  await adjustSalesCustomerBalance(env, bot.id, customer.id, -Number(order.amountToman), "purchase", "sales_order", order.orderId, "خرید " + order.plan.title);
  const owner = await env.PASARGUARD_DB.prepare("SELECT * FROM users WHERE id=?").bind(bot.user_id).first();
  try { return await provisionSalesOrder(env, owner, order.orderId); }
  catch (error) {
    try {
      await adjustSalesCustomerBalance(env, bot.id, customer.id, Number(order.amountToman), "refund", "sales_order", order.orderId, "بازگشت وجه سفارش ناموفق");
      await env.PASARGUARD_DB.prepare("UPDATE sales_orders SET status='cancelled',error_message=?,updated_at=? WHERE id=?").bind(cleanText(error.message, 800), nowIso(), order.orderId).run();
      await salesReleasePromoForOrder(env, order.orderId);
    } catch (_) {}
    throw error;
  }
}

async function requestSalesTrial(env, bot, customer, options = {}) {
  salesRequireVerifiedPhone(bot, customer);
  await enforceSalesSecurity(env, bot, customer, "trial");
  if (Number(bot.trial_enabled || 0) !== 1) throw new Error("تست رایگان در حال حاضر فعال نیست");
  const origin = options.origin === "miniapp" ? "miniapp" : "bot";
  const existing = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_trials WHERE bot_id=? AND customer_id=?").bind(bot.id, customer.id).first();
  if (existing && existing.status === "delivered") throw new Error("شما قبلاً تست رایگان دریافت کرده‌اید");
  const trialId = existing?.id || id("trial");
  if (!existing) await env.PASARGUARD_DB.prepare("INSERT INTO sales_trials(id,bot_id,customer_id,status,origin,created_at,updated_at) VALUES(?,?,?,'provisioning',?,?,?)").bind(trialId, bot.id, customer.id, origin, nowIso(), nowIso()).run();
  else await env.PASARGUARD_DB.prepare("UPDATE sales_trials SET status='provisioning',origin=?,error_message=NULL,updated_at=? WHERE id=?").bind(origin, nowIso(), trialId).run();
  const fullBot = await getResellerBotById(env, bot.id);
  const agency = { id: fullBot.agency_id, panel_username: fullBot.panel_username, panel_password_enc: fullBot.panel_password_enc };
  const username = normalizeUsername("test_" + String(customer.telegram_id).slice(-8) + "_" + trialId.slice(-5));
  const durationHours = Math.max(1, Math.min(720, Number(bot.trial_duration_hours || (Number(bot.trial_duration_days || 1) * 24))));
  const dataBytes = Math.max(1024 * 1024, Number(bot.trial_data_limit_bytes || (100 * 1024 * 1024)));
  try {
    const payload = { username, status: "active", data_limit: dataBytes, expire: new Date(Date.now() + durationHours * 3600000).toISOString(), data_limit_reset_strategy: "no_reset", note: "Free trial / telegram " + customer.telegram_id };
    const location = await env.PASARGUARD_DB.prepare("SELECT group_ids_json FROM sales_locations WHERE bot_id=? AND status='active' ORDER BY sort_order,created_at LIMIT 1").bind(bot.id).first();
    const groups = salesGroupIds(location); if (groups.length) payload.group_ids = groups;
    let created;
    try { created = await agencyPasarguardRequest(env, agency, "POST", "/api/user", payload); }
    catch (error) { if (error.status === 409) created = await agencyPasarguardRequest(env, agency, "GET", "/api/user/" + encodeURIComponent(username)); else throw error; }
    let subscriptionUrl = cleanText(created.subscription_url || created?.data?.subscription_url, 2000);
    if (subscriptionUrl?.startsWith("/")) subscriptionUrl = pasarguardBaseUrl(await getSettings(env)) + subscriptionUrl;
    await env.PASARGUARD_DB.prepare("UPDATE sales_trials SET status='delivered',remote_user_id=?,remote_username=?,subscription_url=?,updated_at=? WHERE id=?").bind(String(created.id || created?.data?.id || ""), username, subscriptionUrl, nowIso(), trialId).run();
    const trialText = await salesBotText(env, bot.id, "trial", "این سرویس فقط برای تست کیفیت ارائه شده است.");
    if (origin !== "miniapp") {
      await sendSalesServiceDelivery(env, bot, customer.telegram_id, { title: "تست رایگان شما آماده شد", planTitle: trialText, username, volumeBytes: dataBytes, durationHours, subscriptionUrl });
    }
    await salesEvent(env, bot.id, customer.id, "trial_delivered", { trialId, username, durationHours, dataBytes, origin });
    return { id: trialId, status: "delivered", username, subscriptionUrl, durationHours, dataBytes, title: trialText, origin };
  } catch (error) { await env.PASARGUARD_DB.prepare("UPDATE sales_trials SET status='failed',error_message=?,updated_at=? WHERE id=?").bind(cleanText(error.message, 800), nowIso(), trialId).run(); throw error; }
}

async function rejectSalesOrder(env, ownerUser, orderId) {
  const order = await env.PASARGUARD_DB.prepare(`
    SELECT o.*,rb.user_id AS owner_user_id,rb.id AS reseller_bot_id,c.telegram_id AS customer_telegram_id,p.title AS plan_title
    FROM sales_orders o JOIN reseller_bots rb ON rb.id=o.bot_id JOIN sales_customers c ON c.id=o.customer_id
    JOIN sales_plans p ON p.id=o.plan_id WHERE o.id=?
  `).bind(orderId).first();
  if (!order || Number(order.owner_user_id) !== Number(ownerUser.id)) throw new Error("سفارش پیدا نشد");
  const result = await env.PASARGUARD_DB.prepare(`
    UPDATE sales_orders SET status='rejected',updated_at=?,reviewed_at=?,reviewed_by=?
    WHERE id=? AND status IN ('pending_review','provision_failed')
  `).bind(nowIso(), nowIso(), ownerUser.id, order.id).run();
  if (!Number(result?.meta?.changes || 0)) throw new Error("این سفارش قابل ردکردن نیست");
  if (order.payment_method === "wallet") {
    try { await adjustSalesCustomerBalance(env, order.bot_id, order.customer_id, Number(order.amount_toman), "refund", "sales_order", order.id, "بازگشت وجه سفارش ردشده"); } catch (_) {}
  }
  try { await salesReleasePromoForOrder(env, order.id); } catch (_) {}
  const bot = await getResellerBotById(env, order.reseller_bot_id);
  if (order.origin !== "miniapp") {
    await resellerTelegramApi(env, bot, "sendMessage", {
      chat_id: order.customer_telegram_id,
      text: "❌ <b>رسید سفارش تأیید نشد</b>\nپلن: <b>" + botEscape(order.plan_title) + "</b>\nبرای پیگیری با پشتیبانی فروشنده تماس بگیرید.",
      parse_mode: "HTML",
      reply_markup: { inline_keyboard: [[{ text: "📦 سفارش‌های من", callback_data: "sale:orders" }]] }
    });
  }
  await audit(env, ownerUser.id, "sales_order_rejected", { orderId: order.id });
  return order;
}

async function salesHandleCustomerCallback(env, bot, callback) {
  if (!callback.message?.chat?.id) return;
  const chatId = callback.message.chat.id;
  const customer = await ensureSalesCustomer(env, bot, callback.from);
  const data = String(callback.data || "");
  try { await resellerTelegramApi(env, bot, "answerCallbackQuery", { callback_query_id: callback.id, text: "در حال انجام…", cache_time: 0 }); } catch (_) {}
  const joinStatus = await resellerRequiredJoinStatus(env, bot, callback.from.id, String(callback.from.id || "") === String(bot.owner_telegram_id || ""), data === "sale:join:check");
  if (data === "sale:join:check") {
    if (!joinStatus.ok) return sendResellerJoinPrompt(env, bot, chatId, joinStatus.missing, callback.message.message_id);
    await salesSessionClear(env, bot.id, customer.telegram_id);
    return salesCustomerSendOrEdit(env, bot, { customer, chatId, messageId: callback.message.message_id }, "home");
  }
  if (!joinStatus.ok) return sendResellerJoinPrompt(env, bot, chatId, joinStatus.missing, callback.message.message_id);
  const target = { customer, chatId, messageId: callback.message.message_id };
  if (data === "sale:home") { await salesSessionClear(env, bot.id, customer.telegram_id); return salesCustomerSendOrEdit(env, bot, target, "home"); }
  if (data === "sale:group:services") return salesCustomerSendOrEdit(env, bot, target, "group_services");
  if (data === "sale:group:account") return salesCustomerSendOrEdit(env, bot, target, "group_account");
  if (data === "sale:group:rewards") return salesCustomerSendOrEdit(env, bot, target, "group_rewards");
  if (data === "sale:group:support") return salesCustomerSendOrEdit(env, bot, target, "group_support");
  if (data === "sale:locations") {
    await salesSessionClear(env, bot.id, customer.telegram_id);
    return salesCustomerSendOrEdit(env, bot, target, "locations");
  }
  if (data === "sale:categories") {
    const session = await salesSessionGet(env, bot.id, customer.telegram_id);
    const locationId = session?.data?.locationId;
    if (!locationId) return salesCustomerSendOrEdit(env, bot, target, "locations");
    return salesCustomerSendOrEdit(env, bot, target, "categories", { locationId });
  }
  if (data === "sale:plans") return salesCustomerSendOrEdit(env, bot, target, "locations");
  if (data === "sale:noop") return;
  if (data === "sale:orders") return salesCustomerSendOrEdit(env, bot, target, "orders");
  if (data === "sale:services") return salesCustomerSendOrEdit(env, bot, target, "services");
  if (data === "sale:wallet") return salesCustomerSendOrEdit(env, bot, target, "wallet");
  if (data === "sale:account") return salesCustomerSendOrEdit(env, bot, target, "account");
  if (data === "sale:referral") return sendSalesReferralView(env, bot, customer, chatId);
  if (data === "sale:promo") return salesCustomerSendOrEdit(env, bot, target, "promo");
  if (data === "sale:promo:enter") {
    await salesSessionSet(env, bot.id, customer.telegram_id, "promo_code", {});
    await resellerTelegramApi(env, bot, "sendMessage", { chat_id: chatId, text: "🎟 کد تخفیف یا هدیه را ارسال کنید.\nمثال: <code>WELCOME20</code>", parse_mode: "HTML" });
    return;
  }
  if (data === "sale:support") {
    const settings = await getSettings(env);
    const appUrl = salesMiniAppUrl(bot, settings);
    if (!appUrl) throw new Error("آدرس مینی‌اپ تنظیم نشده است");
    return resellerTelegramApi(env, bot, "sendMessage", {
      chat_id: chatId,
      text: "🎫 مرکز پشتیبانی داخل مینی‌اپ باز می‌شود؛ تیکت‌های شما و پاسخ نماینده فقط همان‌جا نمایش داده می‌شوند.",
      reply_markup: { inline_keyboard: [[{ text: "🎫 بازکردن مرکز پشتیبانی", web_app: { url: appUrl + "#support" } }]] }
    });
  }
  if (data === "sale:help") return salesCustomerSendOrEdit(env, bot, target, "help");
  if (data.startsWith("sale:help:")) return salesCustomerSendOrEdit(env, bot, target, "help_article", { key: data.slice("sale:help:".length) });
  if (data === "sale:trial") {
    await resellerTelegramApi(env, bot, "answerCallbackQuery", { callback_query_id: callback.id, text: "در حال ساخت تست…", cache_time: 0 });
    await requestSalesTrial(env, bot, customer);
    return;
  }
  if (data === "sale:wallet:charge") {
    const methods = resellerPaymentMethodOrder(bot).filter(method => method !== "wallet" && resellerPaymentMethodEnabled(bot, method, "recharge"));
    if (!methods.length) throw new Error("هیچ روش فعالی برای شارژ کیف پول تنظیم نشده است");
    if (methods.length === 1) {
      const method = methods[0];
      await salesSessionSet(env, bot.id, customer.telegram_id, "wallet_amount", { paymentMethod: method });
      await resellerTelegramApi(env, bot, "sendMessage", { chat_id: chatId, text: method === "blupal" ? "💠 مبلغ شارژ آنلاین را به تومان ارسال کنید.\nمثال: 100000" : "💰 مبلغ شارژ کارت‌به‌کارت را به تومان ارسال کنید.\nمثال: 100000" });
      return;
    }
    const keyboard = methods.map(method => method === "blupal"
      ? [{ text: "💠 پرداخت آنلاین بلوپال", callback_data: "sale:wallet:online" }]
      : [{ text: "💳 کارت‌به‌کارت و رسید", callback_data: "sale:wallet:card" }]);
    keyboard.push([{ text: "↩️ بازگشت", callback_data: "sale:wallet" }]);
    return resellerTelegramApi(env, bot, "sendMessage", {
      chat_id: chatId,
      text: "💳 <b>روش شارژ کیف پول</b>\nروش پرداخت موردنظر را انتخاب کنید.",
      parse_mode: "HTML",
      reply_markup: { inline_keyboard: keyboard }
    });
  }
  if (data === "sale:wallet:card" || data === "sale:wallet:online") {
    const method = data.endsWith(":online") ? "blupal" : "card";
    resellerRequirePaymentMethod(bot, method, "recharge");
    await salesSessionSet(env, bot.id, customer.telegram_id, "wallet_amount", { paymentMethod: method });
    await resellerTelegramApi(env, bot, "sendMessage", { chat_id: chatId, text: method === "blupal" ? "💠 مبلغ شارژ آنلاین را به تومان ارسال کنید.\nمثال: 100000" : "💰 مبلغ شارژ کارت‌به‌کارت را به تومان ارسال کنید.\nمثال: 100000" });
    return;
  }
  if (data.startsWith("sale:loc:")) {
    const locationId = data.slice(9);
    const location = await env.PASARGUARD_DB.prepare(
      "SELECT id FROM sales_locations WHERE id=? AND bot_id=? AND status='active'"
    ).bind(locationId, bot.id).first();
    if (!location) throw new Error("لوکیشن انتخاب‌شده دیگر فعال نیست");
    await salesSessionSet(env, bot.id, customer.telegram_id, "purchase_location", { locationId });
    return salesCustomerSendOrEdit(env, bot, target, "categories", { locationId });
  }
  if (data.startsWith("sale:cat:")) {
    const session = await salesSessionGet(env, bot.id, customer.telegram_id);
    const locationId = session?.data?.locationId;
    if (!locationId) return salesCustomerSendOrEdit(env, bot, target, "locations");
    const categoryId = data.slice(9);
    return salesCustomerSendOrEdit(env, bot, target, "plans", {
      locationId,
      categoryId: categoryId === "none" ? null : categoryId,
      uncategorized: categoryId === "none"
    });
  }
  if (data.startsWith("sale:buy:")) {
    const order = await createSalesOrder(env, bot, customer, data.slice(9));
    await sendSalesPaymentInstructions(env, bot, customer, order);
    return;
  }
  if (data.startsWith("sale:obuy:")) {
    const order = await createSalesOrder(env, bot, customer, data.slice(10), { paymentMethod: "blupal" });
    try {
      const invoice = await createSalesBlupalInvoice(env, bot, customer, "order", order.orderId, order.amountToman);
      await sendSalesBlupalInvoiceMessage(env, bot, customer, invoice, "پرداخت آنلاین سفارش", "پلن: " + order.plan.title);
    } catch (error) {
      await env.PASARGUARD_DB.prepare("UPDATE sales_orders SET status='cancelled',updated_at=? WHERE id=?").bind(nowIso(),order.orderId).run();
      try { await salesReleasePromoForOrder(env, order.orderId); } catch (_) {}
      throw error;
    }
    return;
  }
  if (data.startsWith("sale:wbuy:")) {
    await purchaseSalesPlanFromWallet(env, bot, customer, data.slice(10));
    return;
  }
  if (data.startsWith("sale:paystatus:")) {
    const paymentId = data.slice("sale:paystatus:".length);
    const payment = await salesBlupalPaymentStatus(env, bot, customer, paymentId);
    const done = !!payment.processed_at;
    await resellerTelegramApi(env, bot, "answerCallbackQuery", {
      callback_query_id: callback.id,
      text: done ? "✅ پرداخت تأیید و پردازش شد" : ("وضعیت: " + normalizePaymentStatus(payment.status)),
      show_alert: !done,
      cache_time: 0
    });
    if (done) return salesCustomerSendOrEdit(env, bot, target, payment.target_type === "wallet" ? "wallet" : "services");
    return;
  }
  if (data.startsWith("sale:service:refresh:")) {
    const serviceId = data.slice("sale:service:refresh:".length);
    await syncSalesService(env, bot, customer, serviceId);
    return salesCustomerSendOrEdit(env, bot, target, "service_detail", { serviceId });
  }
  if (data.startsWith("sale:service:revoke_confirm:")) {
    const serviceId = data.slice("sale:service:revoke_confirm:".length);
    const service = await getSalesServiceOrder(env, bot, customer, serviceId);
    return resellerTelegramApi(env, bot, "editMessageText", {
      chat_id: chatId, message_id: callback.message.message_id, parse_mode: "HTML",
      text: "🔐 <b>تعویض لینک اشتراک</b>\n━━━━━━━━━━━━━━\nلینک فعلی سرویس <code>" + botEscape(service.remote_username) + "</code> از اعتبار خارج می‌شود و لینک جدید ساخته خواهد شد. ادامه می‌دهید؟",
      reply_markup: { inline_keyboard: [[{ text: "✅ بله، تعویض شود", callback_data: "sale:service:revoke:" + serviceId }], [{ text: "لغو", callback_data: "sale:service:" + serviceId }]] }
    });
  }
  if (data.startsWith("sale:service:revoke:")) {
    const serviceId = data.slice("sale:service:revoke:".length);
    await revokeSalesServiceSubscription(env, bot, customer, serviceId);
    return salesCustomerSendOrEdit(env, bot, target, "service_detail", { serviceId });
  }
  if (data.startsWith("sale:service:")) {
    const serviceId = data.slice("sale:service:".length);
    return salesCustomerSendOrEdit(env, bot, target, "service_detail", { serviceId });
  }
  if (data.startsWith("sale:volume:")) {
    const targetOrderId = data.slice("sale:volume:".length);
    await getSalesServiceOrder(env, bot, customer, targetOrderId);
    await salesSessionSet(env, bot.id, customer.telegram_id, "volume_target", { targetOrderId });
    const view = await salesCustomerPlansView(env, bot, customer, { planType: "volume" });
    view.reply_markup.inline_keyboard = view.reply_markup.inline_keyboard.map(row => row.map(btn => {
      if (btn.callback_data?.startsWith("sale:buy:")) return { ...btn, callback_data: "sale:vplan:" + btn.callback_data.slice(9) };
      if (btn.callback_data?.startsWith("sale:obuy:")) return { ...btn, callback_data: "sale:ovplan:" + btn.callback_data.slice(10) };
      if (btn.callback_data?.startsWith("sale:wbuy:")) return { ...btn, callback_data: "sale:vwbuy:" + btn.callback_data.slice(10) };
      return btn;
    }));
    await resellerTelegramApi(env, bot, "editMessageText", { chat_id: chatId, message_id: callback.message.message_id, text: view.text, parse_mode: "HTML", reply_markup: view.reply_markup });
    return;
  }
  if (data.startsWith("sale:vplan:") || data.startsWith("sale:vwbuy:") || data.startsWith("sale:ovplan:")) {
    const wallet = data.startsWith("sale:vwbuy:"), online = data.startsWith("sale:ovplan:");
    const planId = data.slice(online ? 12 : 11);
    const session = await salesSessionGet(env, bot.id, customer.telegram_id);
    if (session?.state !== "volume_target" || !session.data.targetOrderId) throw new Error("انتخاب سرویس افزایش حجم منقضی شده است");
    if (wallet) await purchaseSalesPlanFromWallet(env, bot, customer, planId, { orderType: "volume", targetOrderId: session.data.targetOrderId });
    else {
      const order = await createSalesOrder(env, bot, customer, planId, { orderType: "volume", targetOrderId: session.data.targetOrderId, paymentMethod: online ? "blupal" : "card" });
      if (online) {
        try { const invoice = await createSalesBlupalInvoice(env, bot, customer, "order", order.orderId, order.amountToman); await sendSalesBlupalInvoiceMessage(env, bot, customer, invoice, "پرداخت آنلاین افزایش حجم", "پلن: " + order.plan.title); }
        catch (error) { await env.PASARGUARD_DB.prepare("UPDATE sales_orders SET status='cancelled',updated_at=? WHERE id=?").bind(nowIso(),order.orderId).run(); try { await salesReleasePromoForOrder(env, order.orderId); } catch (_) {} throw error; }
      } else await sendSalesPaymentInstructions(env, bot, customer, order);
    }
    return;
  }
  if (data.startsWith("sale:renew:")) {
    const targetOrderId = data.slice(11);
    const service = await env.PASARGUARD_DB.prepare("SELECT id FROM sales_orders WHERE id=? AND bot_id=? AND customer_id=? AND status='delivered'")
      .bind(targetOrderId, bot.id, customer.id).first();
    if (!service) throw new Error("سرویس قابل تمدید پیدا نشد");
    await salesSessionSet(env, bot.id, customer.telegram_id, "renew_target", { targetOrderId });
    const view = await salesCustomerPlansView(env, bot, customer, { planType: "renew" });
    view.text = "♻️ <b>پلن تمدید را انتخاب کنید</b>\n━━━━━━━━━━━━━━\n" + view.text.split("━━━━━━━━━━━━━━\n").slice(1).join("━━━━━━━━━━━━━━\n");
    view.reply_markup.inline_keyboard = view.reply_markup.inline_keyboard.map(row => row.map(btn => {
      if (btn.callback_data?.startsWith("sale:buy:")) return { ...btn, callback_data: "sale:rplan:" + btn.callback_data.slice(9) };
      if (btn.callback_data?.startsWith("sale:obuy:")) return { ...btn, callback_data: "sale:orplan:" + btn.callback_data.slice(10) };
      if (btn.callback_data?.startsWith("sale:wbuy:")) return { ...btn, callback_data: "sale:rwbuy:" + btn.callback_data.slice(10) };
      return btn;
    }));
    await resellerTelegramApi(env, bot, "editMessageText", { chat_id: chatId, message_id: callback.message.message_id, text: view.text, parse_mode: "HTML", reply_markup: view.reply_markup });
    return;
  }
  if (data.startsWith("sale:rplan:") || data.startsWith("sale:rwbuy:") || data.startsWith("sale:orplan:")) {
    const wallet = data.startsWith("sale:rwbuy:"), online = data.startsWith("sale:orplan:");
    const planId = data.slice(online ? 12 : 11);
    const session = await salesSessionGet(env, bot.id, customer.telegram_id);
    if (session?.state !== "renew_target" || !session.data.targetOrderId) throw new Error("انتخاب سرویس تمدید منقضی شده است");
    if (wallet) await purchaseSalesPlanFromWallet(env, bot, customer, planId, { orderType: "renewal", targetOrderId: session.data.targetOrderId });
    else {
      const order = await createSalesOrder(env, bot, customer, planId, { orderType: "renewal", targetOrderId: session.data.targetOrderId, paymentMethod: online ? "blupal" : "card" });
      if (online) {
        try { const invoice = await createSalesBlupalInvoice(env, bot, customer, "order", order.orderId, order.amountToman); await sendSalesBlupalInvoiceMessage(env, bot, customer, invoice, "پرداخت آنلاین تمدید", "پلن: " + order.plan.title); }
        catch (error) { await env.PASARGUARD_DB.prepare("UPDATE sales_orders SET status='cancelled',updated_at=? WHERE id=?").bind(nowIso(),order.orderId).run(); try { await salesReleasePromoForOrder(env, order.orderId); } catch (_) {} throw error; }
      } else await sendSalesPaymentInstructions(env, bot, customer, order);
    }
    return;
  }
  throw new Error("این گزینه دیگر معتبر نیست");
}

function resellerOwnerMapCallback(data) {
  const value = String(data || "");
  if (value === "bot:sales") return "owner:home";
  if (value.startsWith("bot:sales:")) return "owner:" + value.slice("bot:sales:".length);
  if (value === "bot:home") return "sale:home";
  if (value === "bot:cancel") return "owner:home";
  return value;
}

function resellerOwnerMapMarkup(replyMarkup) {
  if (!replyMarkup?.inline_keyboard) return replyMarkup;
  return {
    ...replyMarkup,
    inline_keyboard: replyMarkup.inline_keyboard.map(row => row.map(button => {
      if (!button.callback_data) return { ...button };
      return { ...button, callback_data: resellerOwnerMapCallback(button.callback_data) };
    }))
  };
}

async function resellerOwnerAccount(env, bot, from) {
  const actorAccount = await ensureTelegramBotUser(env, from);
  const telegramId = String(from?.id || "");
  if (!telegramId) throw new Error("شناسه تلگرام دریافت نشد");
  if (Number(actorAccount.user.id) === Number(bot.user_id) && telegramId === String(bot.owner_telegram_id || "")) {
    return {
      ...actorAccount,
      ownerUser: actorAccount.user,
      actorUser: actorAccount.user,
      resellerActor: { telegram_id: telegramId, role: "owner", label: bot.parent_bot_id ? "نماینده فروش" : resellerLicenseTypeLabel(bot.license_type), permissions: ["*"] }
    };
  }
  const staff = await env.PASARGUARD_DB.prepare(`
    SELECT * FROM reseller_staff WHERE bot_id=? AND telegram_id=? AND status='active'
  `).bind(bot.id, telegramId).first();
  if (!staff) throw new Error("این بخش فقط در اختیار تیم مدیریت ربات است");
  const ownerUser = await env.PASARGUARD_DB.prepare("SELECT * FROM users WHERE id=? AND status='active'").bind(bot.user_id).first();
  if (!ownerUser) throw new Error("حساب مالک ربات در دسترس نیست");
  const role = RESELLER_STAFF_ROLES[staff.role] ? staff.role : "support";
  return {
    ...actorAccount,
    user: { ...ownerUser, telegram_id: telegramId },
    ownerUser,
    actorUser: actorAccount.user,
    resellerActor: {
      id: staff.id,
      telegram_id: telegramId,
      role,
      label: resellerStaffRoleLabel(role),
      permissions: [...RESELLER_STAFF_ROLES[role].permissions],
      display_name: staff.display_name || actorAccount.user.first_name || actorAccount.user.username || telegramId
    }
  };
}


