    [{ text: "🔄 استعلام فاکتورهای معلق", callback_data: "owner:payment:sync" }, { text: "🔐 تعویض توکن Webhook", callback_data: "owner:payment:regenerate" }],
    [{ text: "↩️ مدیریت", callback_data: "owner:home" }]
