async function authenticateSalesMiniApp(request, env, botId) {
  await ensureDb(env);
  const bot = await getResellerBotById(env, botId);
  if (!bot) throw new Error("ربات نمایندگی پیدا نشد");
  try { await ensureResellerBotRuntimeCurrent(env, bot); } catch (_) {}
  if (bot.status !== "active") throw new Error("فروش این ربات موقتاً متوقف است");
  resellerRequireActiveLicense(bot);
  const initData = request.headers.get("x-telegram-init-data") || "";
  if (initData) {
    const telegramUser = await validateTelegramInitData(initData, await resellerBotToken(env, bot), 86400);
    const isOwner = String(telegramUser.id || "") === String(bot.owner_telegram_id || "");
    const joinStatus = await resellerRequiredJoinStatus(env, bot, telegramUser.id, isOwner);
    if (!joinStatus.ok) throw joinRequiredError(joinStatus.missing);
    const customer = await ensureSalesCustomer(env, bot, telegramUser);
    return { bot, customer, telegramUser, authMode: "telegram" };
  }
  const session = await webSessionFromRequest(request, env, "sales", bot.id);
  if (!session?.customer_id) throw webAuthError("برای ورود به فروشگاه، کد یک‌بارمصرف دریافت کنید");
  const customer = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_customers WHERE id=? AND bot_id=? AND status='active'").bind(session.customer_id, bot.id).first();
  if (!customer) throw webAuthError("نشست نسخه وب معتبر نیست؛ دوباره وارد شوید");
  const isOwner = String(customer.telegram_id || "") === String(bot.owner_telegram_id || "");
  const joinStatus = await resellerRequiredJoinStatus(env, bot, customer.telegram_id, isOwner);
  if (!joinStatus.ok) throw joinRequiredError(joinStatus.missing);
  return { bot, customer, telegramUser: { id: customer.telegram_id, username: customer.username, first_name: customer.first_name, last_name: customer.last_name }, authMode: "web" };
}

async function salesMiniAppBootstrap(request, env, botId) {
  try {
    const { bot, customer, authMode } = await authenticateSalesMiniApp(request, env, botId);
    const [categories, locations, plans, orders, ledger, walletRequests, referralCount, trial, textRows, notifications, tickets, paymentInvoices] = await Promise.all([
      env.PASARGUARD_DB.prepare("SELECT id,title,emoji,sort_order FROM sales_categories WHERE bot_id=? AND status='active' ORDER BY sort_order,created_at").bind(bot.id).all(),
      env.PASARGUARD_DB.prepare("SELECT id,title,emoji,description,sort_order FROM sales_locations WHERE bot_id=? AND status='active' ORDER BY sort_order,created_at").bind(bot.id).all(),
      env.PASARGUARD_DB.prepare(`SELECT p.id,p.title,p.data_limit_bytes,p.duration_days,p.price_toman,p.category_id,p.location_id,p.plan_type,c.title AS category_title,c.emoji AS category_emoji,l.title AS location_title,l.emoji AS location_emoji FROM sales_plans p LEFT JOIN sales_categories c ON c.id=p.category_id LEFT JOIN sales_locations l ON l.id=p.location_id WHERE p.bot_id=? AND p.status='active' ORDER BY p.sort_order,p.price_toman,p.created_at`).bind(bot.id).all(),
      env.PASARGUARD_DB.prepare(`SELECT o.id,o.amount_toman,o.original_amount_toman,o.discount_toman,o.promo_code,o.cashback_toman,o.status,o.order_type,o.target_order_id,o.payment_method,o.origin,o.remote_username,o.subscription_url,o.remote_status,o.remote_data_limit,o.remote_used_traffic,o.remote_expire,o.remote_online_at,o.remote_last_synced_at,o.error_message,o.created_at,o.updated_at,p.title AS plan_title,p.data_limit_bytes,p.duration_days,p.category_id,p.location_id,c.title AS category_title,c.emoji AS category_emoji,l.title AS location_title,l.emoji AS location_emoji FROM sales_orders o JOIN sales_plans p ON p.id=o.plan_id LEFT JOIN sales_categories c ON c.id=p.category_id LEFT JOIN sales_locations l ON l.id=p.location_id WHERE o.bot_id=? AND o.customer_id=? ORDER BY o.created_at DESC LIMIT 80`).bind(bot.id,customer.id).all(),
      env.PASARGUARD_DB.prepare("SELECT type,amount,balance_after,description,created_at FROM sales_customer_ledger WHERE customer_id=? ORDER BY created_at DESC LIMIT 30").bind(customer.id).all(),
      env.PASARGUARD_DB.prepare("SELECT id,amount_toman,status,bonus_toman,origin,created_at,updated_at FROM sales_wallet_requests WHERE bot_id=? AND customer_id=? ORDER BY created_at DESC LIMIT 20").bind(bot.id,customer.id).all(),
      env.PASARGUARD_DB.prepare("SELECT COUNT(*) AS c FROM sales_customers WHERE referrer_customer_id=?").bind(customer.id).first(),
      env.PASARGUARD_DB.prepare("SELECT id,status,origin,remote_username,subscription_url,error_message,created_at,updated_at FROM sales_trials WHERE bot_id=? AND customer_id=?").bind(bot.id,customer.id).first(),
      env.PASARGUARD_DB.prepare("SELECT text_key,text_value FROM reseller_bot_texts WHERE bot_id=?").bind(bot.id).all(),
      env.PASARGUARD_DB.prepare("SELECT id,order_id,type,title,message,status,created_at,read_at FROM sales_notifications WHERE bot_id=? AND customer_id=? ORDER BY created_at DESC LIMIT 40").bind(bot.id,customer.id).all(),
      env.PASARGUARD_DB.prepare("SELECT id,public_code,category,priority,subject,status,last_message_at,created_at,updated_at,closed_at FROM sales_tickets WHERE bot_id=? AND customer_id=? ORDER BY last_message_at DESC LIMIT 50").bind(bot.id,customer.id).all(),
      env.PASARGUARD_DB.prepare("SELECT id,provider_invoice_id,target_type,target_id,amount_toman,final_amount_rial,status,payment_link,card_number,paid_at,processed_at,error_message,created_at,updated_at FROM sales_payment_invoices WHERE bot_id=? AND customer_id=? ORDER BY created_at DESC LIMIT 30").bind(bot.id,customer.id).all()
    ]);
    const orderRows = orders.results || [];
    const services = buildSalesServices(orderRows);
    const activePromo = await salesActivePromoForCustomer(env, bot.id, customer);
    const texts = { ...SALES_TEXT_DEFAULTS };
    for (const row of textRows.results || []) if (SALES_TEXT_LABELS[row.text_key]) texts[row.text_key] = cleanText(row.text_value, 3500) || texts[row.text_key];
    const referralLink = "https://t.me/" + bot.bot_username.replace(/^@/, "") + "?start=ref_" + customer.referral_code;
    return json({
      success: true,
      version: APP_VERSION,
      auth_mode: authMode || "telegram",
      bot: {
        id: bot.id, brand_name: bot.brand_name, bot_username: bot.bot_username,
        support_url: salesSupportUrl(bot), card_holder: bot.card_holder,
        card_number: formatCardNumber(bot.card_number), card_number_raw: normalizeCardNumber(bot.card_number), bank_name: bot.bank_name,
        trial_enabled: Number(bot.trial_enabled || 0) === 1,
        trial_data_limit_bytes: Number(bot.trial_data_limit_bytes || 0),
        trial_duration_days: Number(bot.trial_duration_days || 0),
        trial_duration_hours: Number(bot.trial_duration_hours || Number(bot.trial_duration_days || 1) * 24),
        referral_reward_toman: Number(bot.referral_reward_toman || 0),
        referral_reward_type: String(bot.referral_reward_type || "fixed"),
        referral_reward_percent: Number(bot.referral_reward_percent || 0),
        recharge_bonus_percent: Number(bot.recharge_bonus_percent || 0),
        cashback_enabled: Number(bot.cashback_enabled || 0) === 1,
        cashback_percent: Number(bot.cashback_percent || 0),
        cashback_min_purchase_toman: Number(bot.cashback_min_purchase_toman || 0),
        cashback_max_toman: Number(bot.cashback_max_toman || 0),
        notifications_enabled: Number(bot.notifications_enabled ?? 1) === 1,
        expiry_reminder_hours: Number(bot.expiry_reminder_hours || 48),
        usage_reminder_percent: Number(bot.usage_reminder_percent || 80),
        ticketing_enabled: Number(bot.ticketing_enabled ?? 1) === 1,
        phone_verification_required: Number(bot.phone_verification_required || 0) === 1,
        ticket_auto_close_hours: Number(bot.ticket_auto_close_hours || 72),
        sales_automation_enabled: Number(bot.sales_automation_enabled ?? 1) === 1,
        loyalty_enabled: Number(bot.loyalty_enabled ?? 1) === 1,
        loyalty_profile: String(bot.loyalty_profile || "standard"),
        fraud_protection_enabled: Number(bot.fraud_protection_enabled ?? 1) === 1,
        payment_card_enabled: resellerPaymentMethodEnabled(bot, "card"),
        payment_wallet_enabled: resellerPaymentMethodEnabled(bot, "wallet"),
        payment_methods_order: resellerPaymentMethodOrder(bot),
        payment_default_method: resellerPaymentDefaultMethod(bot, "order"),
        blupal_enabled: resellerPaymentMethodEnabled(bot, "blupal"),
        online_payment_label: "پرداخت آنلاین بلوپال",
        bot_version: APP_VERSION
      },
      customer: {
        id: customer.id, telegram_id: customer.telegram_id, username: customer.username,
        first_name: customer.first_name, last_name: customer.last_name,
        wallet_balance: Number(customer.wallet_balance || 0), referral_code: customer.referral_code,
        customer_type: String(customer.customer_type || "retail"), discount_percent: Number(customer.discount_percent || 0),
        lifetime_spend_toman: Number(customer.lifetime_spend_toman || 0), loyalty_level: String(customer.loyalty_level || "bronze"),
        loyalty_discount_percent: Number(customer.loyalty_discount_percent || 0), last_purchase_at: customer.last_purchase_at || null,
        risk_level: String(customer.risk_level || "normal"),
        phone_number: normalizeSalesPhone(customer.phone_number), phone_verified: salesPhoneVerified(customer),
        phone_verified_at: customer.phone_verified_at || null,
        active_promo: salesPromoPublic(activePromo),
        referral_link: referralLink, referrals_count: Number(referralCount?.c || 0)
      },
      texts,
      categories: categories.results || [], locations: locations.results || [], plans: plans.results || [],
      orders: orderRows, services, ledger: ledger.results || [], wallet_requests: walletRequests.results || [], trial: trial || null,
      notifications: notifications.results || [],
      unread_notifications: (notifications.results || []).filter(row => row.status === "unread").length,
      tickets: tickets.results || [],
      open_tickets: (tickets.results || []).filter(row => row.status !== "closed").length,
      payment_invoices: paymentInvoices.results || []
    });
  } catch (error) {
    if (error?.code === "JOIN_REQUIRED") return json({ success: false, error: error.message, code: "JOIN_REQUIRED", channels: error.channels || [] }, 403);
    if (error?.code === "WEB_LOGIN_REQUIRED") return fail(error.message || "ورود نسخه وب لازم است", 401, "WEB_LOGIN_REQUIRED");
    return fail(error.message || "خطا در ورود به مینی‌اپ", 401, error?.code || "SALES_APP_AUTH_FAILED");
  }
}

async function salesMiniAppAction(request, env, botId) {
  try {
    const { bot, customer } = await authenticateSalesMiniApp(request, env, botId);
    if (bot.status !== "active") throw new Error("فروش این ربات موقتاً متوقف است");
    const body = await parseBody(request);
    const action = String(body.action || "");
    const promoCode = cleanText(body.promo_code, 80);
    const phoneProtectedActions = new Set([
      "create_order", "wallet_buy", "renew_order", "renew_wallet",
      "volume_order", "volume_wallet", "trial", "wallet_charge",
      "ticket_create", "ticket_reply"
    ]);
    if (phoneProtectedActions.has(action)) salesRequireVerifiedPhone(bot, customer);
    if (action === "notifications_read") {
      await env.PASARGUARD_DB.prepare("UPDATE sales_notifications SET status='read',read_at=? WHERE bot_id=? AND customer_id=? AND status='unread'").bind(nowIso(), bot.id, customer.id).run();
      return json({ success: true, message: "همه اعلان‌ها خوانده شدند." });
    }
    if (action === "payment_status") {
      const payment = await salesBlupalPaymentStatus(env, bot, customer, cleanText(body.payment_id, 100));
      const order = payment.target_type === "order" ? await env.PASARGUARD_DB.prepare("SELECT id,status,remote_username,subscription_url,order_type,cashback_toman FROM sales_orders WHERE id=? AND bot_id=? AND customer_id=?").bind(payment.target_id,bot.id,customer.id).first() : null;
      const wallet = payment.target_type === "wallet" ? await env.PASARGUARD_DB.prepare("SELECT id,status,bonus_toman FROM sales_wallet_requests WHERE id=? AND bot_id=? AND customer_id=?").bind(payment.target_id,bot.id,customer.id).first() : null;
      return json({ success: true, payment, order, wallet, message: payment.processed_at ? "پرداخت با موفقیت پردازش شد." : "وضعیت فاکتور بروزرسانی شد." });
    }
    if (action === "ticket_create") {
      const ticket = await createSalesTicket(env, bot, customer, {
        category: body.category, priority: body.priority, subject: body.subject, message: body.message
      });
      return json({ success: true, message: "تیکت " + ticket.public_code + " ثبت شد و در انتظار پاسخ نماینده است.", ticket });
    }
    if (action === "ticket_detail") {
      const detail = await salesTicketDetailForCustomer(env, bot, customer, cleanText(body.ticket_id, 80));
      return json({ success: true, ...detail });
    }
    if (action === "ticket_reply") {
      const ticket = await replySalesTicketByCustomer(env, bot, customer, cleanText(body.ticket_id, 80), body.message);
      return json({ success: true, message: "پاسخ شما ثبت شد.", ticket });
    }
    if (action === "ticket_close") {
      const ticket = await closeSalesTicketByCustomer(env, bot, customer, cleanText(body.ticket_id, 80));
      return json({ success: true, message: "تیکت بسته شد.", ticket });
    }
    if (action === "promo_redeem") {
      const result = await salesActivatePromoCode(env, bot, customer, body.code);
      const message = result.kind === "gift"
        ? "کد هدیه فعال شد و " + botMoney(result.credit) + " تومان به کیف پول اضافه شد."
        : "کد تخفیف فعال شد و روی خرید بعدی اعمال می‌شود.";
      return json({ success: true, message, result });
    }
    if (action === "create_order") {
      const online = String(body.payment_method || "card") === "blupal";
      if (!online) requireSalesPaymentCard(bot);
      const order = await createSalesOrder(env, bot, customer, cleanText(body.plan_id, 80), { origin: "miniapp", promoCode, paymentMethod: online ? "blupal" : "card", status: online ? "payment_pending" : "awaiting_receipt" });
      if (online) {
        try {
          const invoice = await createSalesBlupalInvoice(env, bot, customer, "order", order.orderId, order.amountToman);
          return json({ success: true, message: "فاکتور آنلاین ساخته شد؛ پس از پرداخت، سرویس خودکار تحویل می‌شود.", online_payment: invoice });
        } catch (error) {
          await env.PASARGUARD_DB.prepare("UPDATE sales_orders SET status='cancelled',error_message=?,updated_at=? WHERE id=?").bind(cleanText(error.message,800),nowIso(),order.orderId).run();
          try { await salesReleasePromoForOrder(env, order.orderId); } catch (_) {}
          throw error;
        }
      }
      return json({ success: true, message: "سفارش ساخته شد؛ اطلاعات پرداخت و ثبت رسید داخل مینی‌اپ انجام می‌شود.", payment: salesMiniAppPaymentPayload(bot, "order", order.orderId, order.amountToman, { title: order.plan.title, originalAmountToman: order.originalAmountToman, discountToman: order.discountToman, promoCode: order.promoCode }) });
    }
    if (action === "wallet_buy") {
      const delivered = await purchaseSalesPlanFromWallet(env, bot, customer, cleanText(body.plan_id, 80), { origin: "miniapp", promoCode });
      return json({ success: true, message: "خرید با موفقیت انجام شد.", delivery: { id: delivered.id, title: delivered.plan_title, username: delivered.remote_username, subscription_url: delivered.subscription_url, order_type: delivered.order_type || "new", amount_toman: delivered.amount_toman, discount_toman: delivered.discount_toman, promo_code: delivered.promo_code, cashback_toman: Number(delivered.cashback_toman || 0) } });
    }
    if (action === "renew_order") {
      const online = String(body.payment_method || "card") === "blupal";
      if (!online) requireSalesPaymentCard(bot);
      const targetOrderId = cleanText(body.target_order_id, 80);
      const target = await env.PASARGUARD_DB.prepare("SELECT id FROM sales_orders WHERE id=? AND bot_id=? AND customer_id=? AND status='delivered'").bind(targetOrderId,bot.id,customer.id).first();
      if (!target) throw new Error("سرویس مقصد تمدید پیدا نشد");
      const order = await createSalesOrder(env, bot, customer, cleanText(body.plan_id,80), { orderType: "renewal", targetOrderId, origin: "miniapp", promoCode, paymentMethod: online ? "blupal" : "card", status: online ? "payment_pending" : "awaiting_receipt" });
      if (online) {
        try { const invoice = await createSalesBlupalInvoice(env, bot, customer, "order", order.orderId, order.amountToman); return json({ success: true, message: "فاکتور تمدید آنلاین ساخته شد.", online_payment: invoice }); }
        catch (error) { await env.PASARGUARD_DB.prepare("UPDATE sales_orders SET status='cancelled',error_message=?,updated_at=? WHERE id=?").bind(cleanText(error.message,800),nowIso(),order.orderId).run(); try { await salesReleasePromoForOrder(env,order.orderId); } catch (_) {} throw error; }
      }
      return json({ success: true, message: "سفارش تمدید ساخته شد؛ پرداخت و رسید داخل مینی‌اپ انجام می‌شود.", payment: salesMiniAppPaymentPayload(bot, "order", order.orderId, order.amountToman, { title: order.plan.title, originalAmountToman: order.originalAmountToman, discountToman: order.discountToman, promoCode: order.promoCode }) });
    }
    if (action === "renew_wallet") {
      const targetOrderId = cleanText(body.target_order_id,80);
      const target = await env.PASARGUARD_DB.prepare("SELECT id FROM sales_orders WHERE id=? AND bot_id=? AND customer_id=? AND status='delivered'").bind(targetOrderId,bot.id,customer.id).first();
      if (!target) throw new Error("سرویس مقصد تمدید پیدا نشد");
      const delivered = await purchaseSalesPlanFromWallet(env, bot, customer, cleanText(body.plan_id,80), { orderType: "renewal", targetOrderId, origin: "miniapp", promoCode });
      return json({ success: true, message: "تمدید با موفقیت انجام شد.", delivery: { id: delivered.id, title: delivered.plan_title, username: delivered.remote_username, subscription_url: delivered.subscription_url, order_type: "renewal", amount_toman: delivered.amount_toman, discount_toman: delivered.discount_toman, promo_code: delivered.promo_code, cashback_toman: Number(delivered.cashback_toman || 0) } });
    }
    if (action === "volume_order") {
      const online = String(body.payment_method || "card") === "blupal";
      if (!online) requireSalesPaymentCard(bot);
      const targetOrderId = cleanText(body.target_order_id, 80);
      await getSalesServiceOrder(env, bot, customer, targetOrderId);
      const order = await createSalesOrder(env, bot, customer, cleanText(body.plan_id, 80), { orderType: "volume", targetOrderId, origin: "miniapp", promoCode, paymentMethod: online ? "blupal" : "card", status: online ? "payment_pending" : "awaiting_receipt" });
      if (online) {
        try { const invoice = await createSalesBlupalInvoice(env, bot, customer, "order", order.orderId, order.amountToman); return json({ success: true, message: "فاکتور افزایش حجم آنلاین ساخته شد.", online_payment: invoice }); }
        catch (error) { await env.PASARGUARD_DB.prepare("UPDATE sales_orders SET status='cancelled',error_message=?,updated_at=? WHERE id=?").bind(cleanText(error.message,800),nowIso(),order.orderId).run(); try { await salesReleasePromoForOrder(env,order.orderId); } catch (_) {} throw error; }
      }
      return json({ success: true, message: "سفارش افزایش حجم ساخته شد؛ پرداخت و رسید داخل مینی‌اپ انجام می‌شود.", payment: salesMiniAppPaymentPayload(bot, "order", order.orderId, order.amountToman, { title: order.plan.title, originalAmountToman: order.originalAmountToman, discountToman: order.discountToman, promoCode: order.promoCode }) });
    }
    if (action === "volume_wallet") {
      const targetOrderId = cleanText(body.target_order_id, 80);
      await getSalesServiceOrder(env, bot, customer, targetOrderId);
      const delivered = await purchaseSalesPlanFromWallet(env, bot, customer, cleanText(body.plan_id, 80), { orderType: "volume", targetOrderId, origin: "miniapp", promoCode });
      return json({ success: true, message: "حجم سرویس با موفقیت افزایش یافت.", delivery: { id: delivered.id, title: delivered.plan_title, username: delivered.remote_username, subscription_url: delivered.subscription_url, order_type: "volume", amount_toman: delivered.amount_toman, discount_toman: delivered.discount_toman, promo_code: delivered.promo_code, cashback_toman: Number(delivered.cashback_toman || 0) } });
    }
    if (action === "service_refresh") {
      const service = await syncSalesService(env, bot, customer, cleanText(body.service_id, 80));
      return json({ success: true, message: "اطلاعات سرویس با پنل همگام شد.", service });
    }
    if (action === "service_revoke") {
      const service = await revokeSalesServiceSubscription(env, bot, customer, cleanText(body.service_id, 80));
      return json({ success: true, message: "لینک اشتراک قبلی باطل و لینک جدید ساخته شد.", service });
    }
    if (action === "trial") {
      const delivered = await requestSalesTrial(env, bot, customer, { origin: "miniapp" });
      return json({ success: true, message: "تست رایگان آماده شد.", delivery: { id: delivered.id, title: delivered.title || "تست رایگان", username: delivered.username, subscription_url: delivered.subscriptionUrl, duration_hours: delivered.durationHours, data_limit_bytes: delivered.dataBytes, order_type: "trial" } });
    }
    if (action === "wallet_charge") {
      const amount = clampInt(body.amount, 0, 1000000000000);
      if (amount < 10000) throw new Error("حداقل مبلغ شارژ ۱۰٬۰۰۰ تومان است");
      const walletPaymentMethod = String(body.payment_method || resellerPaymentDefaultMethod(bot, "recharge") || "card").toLowerCase();
      resellerRequirePaymentMethod(bot, walletPaymentMethod, "recharge");
      if (walletPaymentMethod === "blupal") {
        const requestRow = await createSalesBlupalWalletCharge(env, bot, customer, amount);
        return json({ success: true, message: "فاکتور شارژ آنلاین ساخته شد.", online_payment: requestRow.invoice, bonus_percent: requestRow.bonusPercent, bonus_toman: requestRow.bonusAmount });
      }
      requireSalesPaymentCard(bot);
      const requestRow = await salesWalletChargeInstructions(env, bot, customer, amount, { origin: "miniapp", notifyCustomer: false });
      return json({ success: true, message: "اطلاعات کارت آماده شد؛ رسید را همین‌جا ثبت کنید.", payment: salesMiniAppPaymentPayload(bot, "wallet", requestRow.requestId, requestRow.amountToman, { bonusPercent: requestRow.bonusPercent, bonusToman: requestRow.bonusAmount, title: "شارژ کیف پول" }) });
    }
    if (action === "submit_receipt") {
      const result = await submitSalesMiniAppReceipt(env, bot, customer, body);
      return json({ success: true, message: "رسید ثبت شد و در انتظار بررسی نماینده است.", receipt: result });
    }
    return fail("عملیات مینی‌اپ شناخته نشد", 404, "ACTION_NOT_FOUND");
  } catch (error) {
    if (error?.code === "WEB_LOGIN_REQUIRED") return fail(error.message || "ورود نسخه وب لازم است", 401, "WEB_LOGIN_REQUIRED");
    if (error?.code === "JOIN_REQUIRED") return json({ success: false, error: error.message, code: "JOIN_REQUIRED", channels: error.channels || [] }, 403);
    return fail(error.message || "انجام عملیات ناموفق بود", 400, error?.code || "SALES_APP_ACTION_FAILED");
  }
}

