window.verifyPhone=function(){if(!tg||typeof tg.requestContact!=="function"){toast("تلگرام را بروزرسانی کنید و دوباره مینی‌اپ را باز کنید");return}tg.requestContact(function(ok){if(!ok)return toast("ارسال شماره لغو شد");toast("شماره ارسال شد؛ در حال بررسی…");setTimeout(function(){refresh(false)},1700)})};
window.createTicket=async function(){var subject=String(el("ticketSubject").value||"").trim(),message=String(el("ticketMessage").value||"").trim();if(subject.length<3)return toast("موضوع تیکت کوتاه است");if(message.length<5)return toast("شرح درخواست را کامل‌تر بنویسید");try{var d=await api("action",{action:"ticket_create",category:el("ticketCategory").value,priority:el("ticketPriority").value,subject:subject,message:message});el("ticketSubject").value="";el("ticketMessage").value="";toast(d.message);await refresh(false);nav("support")}catch(e){if(e.code==="PHONE_REQUIRED")verifyPhone();else toast(e.message)}};
window.openTicket=async function(encoded){activeTicketId=decodeURIComponent(encoded);try{var d=await api("action",{action:"ticket_detail",ticket_id:activeTicketId}),t=d.ticket,msgs=d.messages||[];var thread=msgs.length?msgs.map(function(m){return'<div class="bubble '+(m.sender_type==="owner"?"owner":"customer")+'">'+esc(m.message_text)+'<small>'+(m.sender_type==="owner"?"نماینده":"شما")+' · '+esc(timeAgo(m.created_at))+'</small></div>'}).join(""):'<div class="empty">پیامی ثبت نشده است.</div>';var actions=t.status==="closed"?'<div class="muted">این تیکت بسته شده است.</div>':'<textarea id="ticketReply" class="input" rows="4" maxlength="3000" placeholder="پاسخ شما"></textarea><div class="row"><button class="btn" onclick="replyTicket()">ارسال پاسخ</button><button class="btn danger" onclick="closeTicket()">بستن تیکت</button></div>';openModal("🎫 "+t.public_code,'<div class="card"><h3>'+esc(t.subject)+'</h3><div class="ticketMeta"><span class="badge">'+esc(ticketStatusLabel(t.status))+'</span><span class="badge">'+esc(ticketCategoryLabel(t.category))+'</span><span class="badge">اولویت '+esc(ticketPriorityLabel(t.priority))+'</span></div></div><div class="ticketThread">'+thread+'</div>'+actions)}catch(e){toast(e.message)}};
window.replyTicket=async function(){var input=el("ticketReply"),message=String(input&&input.value||"").trim();if(message.length<2)return toast("پاسخ را بنویسید");try{var d=await api("action",{action:"ticket_reply",ticket_id:activeTicketId,message:message});toast(d.message);await refresh(false);openTicket(encodeURIComponent(activeTicketId))}catch(e){if(e.code==="PHONE_REQUIRED")verifyPhone();else toast(e.message)}};
window.closeTicket=async function(){if(!activeTicketId)return;var run=async function(ok){if(!ok)return;try{var d=await api("action",{action:"ticket_close",ticket_id:activeTicketId});toast(d.message);closeModal();await refresh(false);nav("support")}catch(e){toast(e.message)}};if(tg&&tg.showConfirm)tg.showConfirm("این تیکت بسته شود؟",run);else run(confirm("این تیکت بسته شود؟"))};
