function showPayment(p){pendingPayment=p;var bonus=Number(p.bonus_toman||0)>0?'<div class="paymentLine"><span>بونس شارژ</span><b>'+money(p.bonus_toman)+'</b></div><div class="paymentLine"><span>اعتبار نهایی</span><b>'+money(p.final_wallet_credit)+'</b></div>':"",discount=Number(p.discount_toman||0)>0?'<div class="paymentLine"><span>قیمت اصلی</span><b class="priceOld">'+money(p.original_amount_toman||p.amount_toman)+'</b></div><div class="paymentLine"><span>کد تخفیف</span><b>'+esc(p.promo_code||"")+'</b></div><div class="paymentLine"><span>تخفیف</span><b style="color:var(--ok)">'+money(p.discount_toman)+'</b></div>':"";openModal(p.target_type==="wallet"?"شارژ کیف پول":"پرداخت سفارش",'<div class="muted">پرداخت و ارسال رسید کاملاً داخل مینی‌اپ انجام می‌شود و پیامی برای حساب کاربری شما در ربات ارسال نخواهد شد.</div><div class="paymentBox"><div class="paymentLine"><span>عنوان</span><b>'+esc(p.title||"پرداخت")+'</b></div>'+discount+'<div class="paymentLine"><span>مبلغ نهایی</span><b>'+money(p.amount_toman)+'</b></div>'+bonus+'<div class="paymentLine"><span>شماره کارت</span><b><code>'+esc(p.card_number||"")+'</code></b></div><div class="paymentLine"><span>صاحب کارت</span><b>'+esc(p.card_holder||"")+'</b></div><div class="paymentLine"><span>بانک</span><b>'+esc(p.bank_name||"")+'</b></div></div><button class="btn secondary full" onclick="copyValue(\''+encodeURIComponent(p.card_number_raw||"")+'\')">📋 کپی شماره کارت</button><label class="upload">🧾 انتخاب تصویر یا فایل رسید<input id="receiptFile" type="file" accept="image/jpeg,image/png,image/webp,application/pdf"></label><textarea id="receiptCaption" class="input" rows="2" placeholder="توضیح اختیاری"></textarea><button id="submitReceiptBtn" class="btn full" onclick="submitReceipt()">ثبت رسید در مینی‌اپ</button><div id="receiptProgress" class="progress">در حال بارگذاری و ثبت رسید…</div>')}
window.submitReceipt=async function(){if(!pendingPayment)return;var input=el("receiptFile"),file=input&&input.files&&input.files[0];if(!file)return toast("ابتدا فایل رسید را انتخاب کنید");if(file.size>5*1024*1024)return toast("حداکثر حجم رسید ۵ مگابایت است");var btn=el("submitReceiptBtn"),progress=el("receiptProgress");btn.disabled=true;progress.style.display="block";try{var data=await readFile(file);var d=await api("action",{action:"submit_receipt",target_type:pendingPayment.target_type,target_id:pendingPayment.target_id,file_name:file.name,mime_type:file.type,file_base64:data,caption:el("receiptCaption").value});toast(d.message);el("modal").classList.remove("show");pendingPayment=null;await refresh()}catch(e){toast(e.message)}finally{btn.disabled=false;progress.style.display="none"}};
function readFile(file){return new Promise(function(resolve,reject){var reader=new FileReader();reader.onload=function(){resolve(String(reader.result||""))};reader.onerror=function(){reject(new Error("خواندن فایل رسید ناموفق بود"))};reader.readAsDataURL(file)})}
