async function refresh(first){try{var fresh=await api("bootstrap",{});state=fresh;render();if(first){el("loading").style.display="none";el("app").style.display="block";el("nav").style.display=window.innerWidth>=900?"flex":"grid";var startPage=String(location.hash||"").replace("#","")||String(tg&&tg.initDataUnsafe&&tg.initDataUnsafe.start_param||"");if(startPage==="payment")startPage="wallet";if(["support","notifications","help","account","wallet","services"].includes(startPage))nav(startPage)}}catch(e){if(first&&e.code==="JOIN_REQUIRED")showJoinGate(e.channels);else if(first&&e.code==="WEB_LOGIN_REQUIRED"&&!isTelegram)showWebLogin();else if(first)el("loading").innerHTML='<div class="joinGate"><div class="card"><div class="emptyIcon">⚠️</div><h3>خطای ورود</h3><div class="muted">'+esc(e.message)+'</div><button class="btn full" style="margin-top:14px" onclick="location.reload()">تلاش مجدد</button></div></div>';else if(e.code==="WEB_LOGIN_REQUIRED"&&!isTelegram)showWebLogin("نشست شما منقضی شده است");else toast(e.message)}}
refresh(true);refreshTimer=setInterval(function(){if(!document.hidden)refresh(false)},12000);if("serviceWorker" in navigator)navigator.serviceWorker.register("/sw.js").catch(function(){});
