function resellerAdminOriginAllowed(request) {
  const origin = String(request.headers.get("origin") || "").trim();
  if (!origin) return true;
  try { return new URL(origin).origin === new URL(request.url).origin; } catch (_) { return false; }
}

async function resellerAdminWebLogin(request, env, botId) {
  await ensureDb(env);
  if (!resellerAdminOriginAllowed(request)) return fail("درخواست نامعتبر است", 403, "BAD_ORIGIN");
  const bot = await getResellerBotById(env, botId);
  if (!bot) return fail("ربات نماینده پیدا نشد", 404, "BOT_NOT_FOUND");
  const body = await parseBody(request);
  const username = cleanText(body.username, 80);
  const password = cleanText(body.password, 200);
  if (!username || !password) return fail("نام کاربری و رمز ورود را وارد کنید", 400, "LOGIN_FIELDS_REQUIRED");
  const owner = await env.PASARGUARD_DB.prepare("SELECT * FROM users WHERE id=?").bind(bot.user_id).first();
  if (!owner || owner.status !== "active") return fail("حساب مالک ربات غیرفعال است", 403, "OWNER_DISABLED");
  if (bot.parent_bot_id) {
    const valid = await verifyResellerControlPassword(bot, username, password);
    if (!valid) return fail("نام کاربری یا رمز مدیریت صحیح نیست", 401, "INVALID_CREDENTIALS");
  } else {
    let verified;
    try { verified = await verifyPasarguardWebCredentials(env, username, password); }
    catch (error) { return fail(error.message || "نام کاربری یا رمز پنل صحیح نیست", 401, "INVALID_CREDENTIALS"); }
    const profile = verified.profile && typeof verified.profile === "object" ? verified.profile : {};
    const sameUsername = String(username).toLowerCase() === String(bot.panel_username || "").toLowerCase();
    const sameRemoteId = profile.id != null && bot.remote_manager_id != null && String(profile.id) === String(bot.remote_manager_id);
    if (!sameUsername && !sameRemoteId) return fail("این حساب اجازه مدیریت این ربات را ندارد", 403, "BOT_ACCESS_DENIED");
  }
  const session = await issueWebSession(request, env, "reseller_admin", { user_id: owner.id, bot_id: bot.id });
  try { await resellerAudit(env, bot, { user: owner, resellerActor: { role: "owner", telegram_id: owner.telegram_id, permissions: [] } }, "web_admin_login", { username, auth: bot.parent_bot_id ? "local" : "pasarguard" }); } catch (_) {}
  return json({ success: true, message: "ورود مدیریت نماینده انجام شد", expires_at: session.expiresAt }, 200, {
    "set-cookie": webCookie(request, resellerAdminWebCookieName(bot.id), session.token, session.seconds)
  });
}

async function resellerAdminWebLogout(request, env, botId) {
  await ensureDb(env);
  const cookieName = await revokeWebSession(request, env, "reseller_admin", botId);
  return json({ success: true, message: "از مدیریت نماینده خارج شدید" }, 200, { "set-cookie": clearWebCookie(request, cookieName) });
}

async function resellerAdminWebAuth(request, env, botId) {
  await ensureDb(env);
  const session = await webSessionFromRequest(request, env, "reseller_admin", botId);
  if (!session?.user_id) return null;
  const bot = await getResellerBotById(env, botId);
  if (!bot || Number(bot.user_id) !== Number(session.user_id)) return null;
  const user = await env.PASARGUARD_DB.prepare("SELECT * FROM users WHERE id=?").bind(session.user_id).first();
  if (!user || user.status !== "active") return null;
  return { user, bot, resellerActor: { role: "owner", telegram_id: user.telegram_id, permissions: [] }, authMode: "web" };
}

async function requireResellerAdminWeb(request, env, botId) {
  const account = await resellerAdminWebAuth(request, env, botId);
  if (!account) return { response: fail("برای ورود به مدیریت نماینده احراز هویت کنید", 401, "WEB_LOGIN_REQUIRED") };
  return account;
}

