function addChannel(c){c=c||{};var d=document.createElement("div");d.className="channelRow";d.innerHTML='<input class="input chId ltr" placeholder="@channel یا -100..." value="'+esc(c.chat_id||"")+'"><input class="input chTitle" placeholder="عنوان کانال" value="'+esc(c.title||"")+'"><input class="input chUrl ltr channelUrl" placeholder="لینک عمومی یا دعوت خصوصی" value="'+esc(c.url||"")+'"><button type="button" class="btn danger small channelRemove">حذف</button>';d.querySelector(".channelRemove").onclick=function(){d.remove()};el("channelsList").appendChild(d)}
