function renderPayments(){var q=String(el("paymentSearch").value||"").toLowerCase(),st=el("paymentStatus").value,rows=(state.invoices||[]).filter(function(x){var hay=[x.provider_invoice_id,x.id,x.username,x.first_name,x.last_name,x.telegram_id,x.amount_toman].join(" ").toLowerCase();return(!q||hay.includes(q))&&(st==="all"||x.status===st)});el("paymentsCount").textContent=num(rows.length)+" فاکتور";el("paymentsList").innerHTML=rows.length?rows.map(paymentCard).join(""):empty("💠","فاکتوری پیدا نشد")}
function fillSettings(){var x=state.settings||{};var values={setBrand:x.brand_name,setWelcome:x.welcome_text,setSupport:x.support_username,setStatus:x.status,setHolder:x.card_holder,setCard:x.card_number,setBank:x.bank_name,setIban:x.iban,setBonus:x.recharge_bonus_percent,setTrialMb:x.trial_data_limit_mb,setTrialHours:x.trial_duration_hours,setReferralType:x.referral_reward_type,setReferralFixed:x.referral_reward_toman,setReferralPercent:x.referral_reward_percent,setLoyaltyProfile:x.loyalty_profile,setCashbackPercent:x.cashback_percent,setCashbackMin:x.cashback_min_purchase_toman,setCashbackMax:x.cashback_max_toman,setExpiryHours:x.expiry_reminder_hours,setUsagePercent:x.usage_reminder_percent,setTicketClose:x.ticket_auto_close_hours,setDailyHour:x.daily_report_hour_utc,setAbandoned:x.abandoned_reminder_minutes,setWinback:x.winback_days,setCooldown:x.order_cooldown_seconds,setMaxPending:x.max_pending_orders,setDailyOrders:x.daily_order_limit,setDailyWallet:x.daily_wallet_charge_limit_toman,setAutoBlock:x.auto_block_risk_score,setBackupHour:x.backup_hour_utc,setBackupRetention:x.backup_retention_days,setDefaultPayment:x.payment_default_method,setPaymentOrder:x.payment_method_order,setBlupalBase:x.blupal_base_url,setBlupalCard:x.blupal_card_number};Object.keys(values).forEach(function(k){if(el(k))el(k).value=values[k]==null?"":values[k]});var checks={setMiniapp:x.miniapp_enabled,setForward:x.forward_enabled,setPayCard:x.payment_card_enabled,setPayWallet:x.payment_wallet_enabled,setBlupal:x.blupal_enabled,setTrial:x.trial_enabled,setLoyalty:x.loyalty_enabled,setCashback:x.cashback_enabled,setNotifications:x.notifications_enabled,setTickets:x.ticketing_enabled,setPhone:x.phone_verification_required,setDailyReport:x.daily_report_enabled,setAutomation:x.sales_automation_enabled,setFraud:x.fraud_protection_enabled,setDuplicateReceipt:x.duplicate_receipt_protection,setAutoBackup:x.auto_backup_enabled};Object.keys(checks).forEach(function(k){if(el(k))el(k).checked=!!checks[k]});el("blupalState").textContent="API Key: "+(x.blupal_api_key_set?"ثبت شده":"ثبت نشده")+(x.blupal_last_error?" · خطا: "+x.blupal_last_error:"")}
function parseDetails(v){try{return JSON.parse(v||"{}")}catch(_){return v||""}}
