function openDownlinePassword(x){openModal("تغییر دسترسی مدیریت "+(x.bot_username||""),'<form id="modalForm"><div class="field"><label>نام کاربری</label><input id="dfUsername" class="input ltr" value="'+esc(x.control_username||("agent_"+String(x.telegram_id||"").slice(-8)))+'" required></div><div class="field"><label>رمز جدید امن</label><input id="dfPassword" class="input ltr" type="password" required></div><button class="btn" type="submit">تغییر نام کاربری و رمز</button></form>');el("modalForm").onsubmit=function(e){e.preventDefault();run({action:"downline_reset_password",id:x.id,control_username:el("dfUsername").value,control_password:el("dfPassword").value}).then(function(d){if(d&&d.credentials)openModal("اطلاعات ورود جدید",'<div class="notice">نام کاربری: <b class="ltr">'+esc(d.credentials.username)+'</b><br>رمز: <b class="ltr">'+esc(d.credentials.password)+'</b><br><small>این رمز فقط همین‌بار نمایش داده می‌شود.</small></div>')})}}
function generateDownlineCredentials(){var suffix=Math.random().toString(36).slice(2,8),tid=String(el("downlineTelegram").value||"").replace(/\D/g,"");el("downlineUsername").value=("agent_"+(tid.slice(-8)||suffix)).slice(0,30);var chars="ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz23456789!@#$%^&*_-+",pass="AAaa22!";for(var i=0;i<10;i++)pass+=chars[Math.floor(Math.random()*chars.length)];el("downlinePassword").value=pass}
