      if (resellerReceiptMatch && request.method === "GET") return resellerAdminReceipt(request, env, decodeURIComponent(resellerReceiptMatch[1]), resellerReceiptMatch[2], decodeURIComponent(resellerReceiptMatch[3]));
      const salesAuthMatch = path.match(/^\/sales-auth\/([^/]+)\/(request-code|verify-code|logout)$/);
